  1→use anyhow::Context;
  2→use serde::{Deserialize, Serialize};
  3→use std::path::{Path, PathBuf};
  4→
  5→/// All fields are Option so partial configs can be merged.
  6→#[derive(Debug, Clone, Serialize, Deserialize, Default, PartialEq)]
  7→pub struct Config {
  8→    pub default_provider_chain: Option<Vec<String>>,
  9→    pub max_concurrent: Option<usize>,
 10→    pub cooldown_seconds: Option<u64>,
 11→    pub log_retention_days: Option<u64>,
 12→    pub default_template: Option<String>,
 13→}
 14→
 15→/// Merge `overlay` on top of `base`.  Non-None overlay values win.
 16→pub fn merge_configs(base: Config, overlay: Config) -> Config {
 17→    Config {
 18→        default_provider_chain: overlay
 19→            .default_provider_chain
 20→            .or(base.default_provider_chain),
 21→        max_concurrent: overlay.max_concurrent.or(base.max_concurrent),
 22→        cooldown_seconds: overlay.cooldown_seconds.or(base.cooldown_seconds),
 23→        log_retention_days: overlay.log_retention_days.or(base.log_retention_days),
 24→        default_template: overlay.default_template.or(base.default_template),
 25→    }
 26→}
 27→
 28→/// Parse JSON bytes into Config, returning a clear error on bad schema.
 29→pub fn parse_config(json: &str) -> anyhow::Result<Config> {
 30→    if json.trim().is_empty() {
 31→        return Ok(Config::default());
 32→    }
 33→    serde_json::from_str(json).context(
 34→        "malformed config: expected schema with optional fields: \
 35→        default_provider_chain, max_concurrent, cooldown_seconds, \
 36→        log_retention_days, default_template",
 37→    )
 38→}
 39→
 40→/// Return the global config path: ~/.bop/config.json
 41→pub fn global_config_path() -> Option<PathBuf> {
 42→    dirs::home_dir().map(|h| h.join(".bop").join("config.json"))
 43→}
 44→
 45→/// Return the project config path: <cwd>/.bop/config.json
 46→pub fn project_config_path() -> PathBuf {
 47→    std::env::current_dir()
 48→        .unwrap_or_else(|_| PathBuf::from("."))
 49→        .join(".bop")
 50→        .join("config.json")
 51→}
 52→
 53→/// Migration warning: config.yaml → config.json
 54→fn warn_if_stale_yaml(json_path: &std::path::Path) {
 55→    let yaml_path = json_path.with_extension("yaml");
 56→    if !json_path.exists() && yaml_path.exists() {
 57→        eprintln!(
 58→            "bop: config file '{}' found but '{}' not present. \
 59→             Please rename your config file: mv {} {}",
 60→            yaml_path.display(),
 61→            json_path.display(),
 62→            yaml_path.display(),
 63→            json_path.display(),
 64→        );
 65→    }
 66→}
 67→
 68→/// Load and merge global + project configs.  Missing files are silently skipped.
 69→/// Returns merged Config and emits a clear error for malformed JSON.
 70→pub fn load_config() -> anyhow::Result<Config> {
 71→    let global = match global_config_path() {
 72→        Some(p) => {
 73→            warn_if_stale_yaml(&p);
 74→            if p.exists() {
 75→                read_config_file(&p)
 76→                    .with_context(|| format!("global config error: {}", p.display()))?
 77→            } else {
 78→                Config::default()
 79→            }
 80→        }
 81→        None => Config::default(),
 82→    };
 83→
 84→    let project_path = project_config_path();
 85→    warn_if_stale_yaml(&project_path);
 86→    let project = if project_path.exists() {
 87→        read_config_file(&project_path)
 88→            .with_context(|| format!("project config error: {}", project_path.display()))?
 89→    } else {
 90→        Config::default()
 91→    };
 92→
 93→    Ok(merge_configs(global, project))
 94→}
 95→
 96→/// Read config from a specific path (used by `bop config get/set`).
 97→pub fn read_config_file(path: &Path) -> anyhow::Result<Config> {
 98→    let json = std::fs::read_to_string(path)
 99→        .with_context(|| format!("cannot read config: {}", path.display()))?;
100→    parse_config(&json).with_context(|| format!("invalid config at {}", path.display()))
101→}
102→
103→/// Write config to a specific path (used by `bop config set`).
104→pub fn write_config_file(path: &Path, cfg: &Config) -> anyhow::Result<()> {
105→    if let Some(parent) = path.parent() {
106→        std::fs::create_dir_all(parent)
107→            .with_context(|| format!("cannot create config dir: {}", parent.display()))?;
108→    }
109→    let json = serde_json::to_string_pretty(cfg).context("failed to serialize config")?;
110→    std::fs::write(path, json)
111→        .with_context(|| format!("cannot write config: {}", path.display()))?;
112→    Ok(())
113→}
