   125→/// Collect all cards for the given state filter into `(label, Vec<CardView>)` groups.
   126→fn collect_card_groups(
   127→    root: &Path,
   128→    state_filter: &str,
   129→) -> anyhow::Result<Vec<(String, Vec<render::CardView>)>> {
   130→    let states = resolve_states(state_filter);
   131→    let mut groups = Vec::new();
   132→
   133→    for state in &states {
   134→        // Collect root-level cards
   135→        let root_cards = collect_card_views(root, state)?;
   136→        if !root_cards.is_empty() {
   137→            groups.push((state.to_string(), root_cards));
   138→        }
   139→
   140→        // Collect team-* directory cards
   141→        if let Ok(entries) = fs::read_dir(root) {
   142→            let mut team_dirs: Vec<_> = entries
   143→                .flatten()
   144→                .filter(|e| {
   145→                    let name = e.file_name();
   146→                    let s = name.to_string_lossy();
   147→                    e.path().is_dir() && s.starts_with("team-")
   148→                })
   149→                .collect();
   150→            team_dirs.sort_by_key(|e| e.file_name());
   151→            for entry in team_dirs {
   152→                let team_name = entry.file_name().to_string_lossy().into_owned();
   153→                let team_cards = collect_card_views(&entry.path(), state)?;
   154→                if !team_cards.is_empty() {
   155→                    groups.push((format!("{}/{}", team_name, state), team_cards));
   156→                }
   157→            }
   158→        }
   159→    }
   160→
   161→    Ok(groups)
   162→}
