 29→// ── Card Scanning for Cleanup ───────────────────────────────────────────────
 30→
 31→#[derive(Debug, Default)]
 32→pub struct ScanResult {
 33→    pub corrupt_cards: Vec<PathBuf>, // Cards with no readable meta.json
 34→    pub old_failed_cards: Vec<PathBuf>, // Cards in failed/ older than threshold
 35→    pub orphan_running_cards: Vec<PathBuf>, // Empty running/ cards with dead PID
 36→    pub target_dirs: Vec<PathBuf>,   // target/ dirs inside cards
 37→}
 38→
 39→pub fn scan_cards_for_cleanup(root: &Path, failed_age_days: u32) -> anyhow::Result<ScanResult> {
 40→    let states = vec!["drafts", "pending", "running", "done", "failed", "merged"];
 41→    let mut result = ScanResult::default();
 42→
 43→    for state in &states {
 44→        scan_state_dir_for_cleanup(root, state, failed_age_days, &mut result)?;
 45→
 46→        // Also scan team-* directories
 47→        if let Ok(entries) = fs::read_dir(root) {
 48→            let mut team_dirs: Vec<_> = entries
 49→                .flatten()
 50→                .filter(|e| {
 51→                    let name = e.file_name();
 52→                    let s = name.to_string_lossy();
 53→                    e.path().is_dir() && s.starts_with("team-")
 54→                })
 55→                .collect();
 56→            team_dirs.sort_by_key(|e| e.file_name());
 57→
 58→            for entry in team_dirs {
 59→                scan_state_dir_for_cleanup(&entry.path(), state, failed_age_days, &mut result)?;
 60→            }
 61→        }
 62→    }
 63→
 64→    Ok(result)
 65→}
 66→
 67→fn scan_state_dir_for_cleanup(
 68→    dir: &Path,
 69→    state: &str,
 70→    failed_age_days: u32,
 71→    result: &mut ScanResult,
 72→) -> anyhow::Result<()> {
 73→    let state_dir = dir.join(state);
 74→    if !state_dir.exists() {
 75→        return Ok(());
 76→    }
 77→
 78→    if let Ok(entries) = fs::read_dir(&state_dir) {
 79→        for entry in entries.flatten() {
 80→            let card_path = entry.path();
 81→            if !card_path.is_dir() {
 82→                continue;
 83→            }
 84→
 85→            let ext = card_path.extension().and_then(|e| e.to_str());
 86→            if !matches!(ext, Some("bop") | Some("jobcard")) {
 87→                continue;
 88→            }
 89→
 90→            // Check for corrupt card (no readable meta.json)
 91→            if bop_core::read_meta(&card_path).is_err() {
 92→                result.corrupt_cards.push(card_path.clone());
 93→                continue;
 94→            }
 95→
 96→            // Check for old failed cards
 97→            if state == "failed" {
 98→                if let Ok(metadata) = fs::metadata(&card_path) {
 99→                    if let Ok(modified) = metadata.modified() {
100→                        let age = std::time::SystemTime::now()
101→                            .duration_since(modified)
102→                            .unwrap_or_default();
103→                        if age.as_secs() > (failed_age_days as u64 * 86400) {
104→                            result.old_failed_cards.push(card_path.clone());
105→                        }
106→                    }
107→                }
108→            }
109→
110→            // Check for orphan running cards (empty with dead PID)
111→            if state == "running" {
112→                // Check if card is empty (no meaningful output/logs)
113→                let is_empty = card_path
114→                    .join("output")
115→                    .read_dir()
116→                    .ok()
117→                    .and_then(|mut d| if d.next().is_none() { Some(true) } else { None })
118→                    .unwrap_or(false);
119→
120→                if is_empty {
121→                    // Check if there are any meaningful log files (ignore events.jsonl)
122→                    let has_meaningful_logs = card_path
123→                        .join("logs")
124→                        .read_dir()
125→                        .ok()
126→                        .and_then(|entries| {
127→                            entries
128→                                .flatten()
129→                                .any(|e| e.file_name() != "events.jsonl" && e.path().is_file())
130→                                .then_some(true)
131→                        })
132→                        .unwrap_or(false);
133→
134→                    // If empty and no meaningful logs, likely orphaned
135→                    if !has_meaningful_logs {
136→                        result.orphan_running_cards.push(card_path.clone());
137→                    }
138→                }
139→            }
140→
141→            // Check for target/ directories inside cards
142→            let target_dir = card_path.join("target");
143→            if target_dir.exists() && target_dir.is_dir() {
144→                result.target_dirs.push(target_dir);
145→            }
146→        }
147→    }
148→
149→    Ok(())
150→}
151→
152→// ── Helper: Calculate directory size ────────────────────────────────────────
153→
154→fn dir_size(path: &Path) -> u64 {
155→    let mut total = 0u64;
156→    if let Ok(entries) = fs::read_dir(path) {
157→        for entry in entries.flatten() {
158→            let path = entry.path();
159→            if let Ok(metadata) = fs::metadata(&path) {
160→                if metadata.is_dir() {
161→                    total += dir_size(&path);
162→                } else {
163→                    total += metadata.len();
164→                }
165→            }
166→        }
167→    }
168→    total
169→}
170→
171→// ── Removal Logic with Dry-Run Support ─────────────────────────────────────
172→
173→#[derive(Debug, Default)]
174→pub struct CleanupStats {
175→    pub corrupt_cards_removed: usize,
176→    pub old_failed_cards_removed: usize,
177→    pub orphan_running_cards_removed: usize,
178→    pub target_dirs_removed: usize,
179→    pub bytes_freed: u64,
180→}
181→
182→pub fn perform_cleanup(scan_result: &ScanResult, dry_run: bool) -> anyhow::Result<CleanupStats> {
183→    let mut stats = CleanupStats::default();
184→
185→    // Remove corrupt cards
186→    for card_path in &scan_result.corrupt_cards {
187→        let size = dir_size(card_path);
188→        if dry_run {
189→            println!(
190→                "[DRY-RUN] Would remove corrupt card: {}",
191→                card_path.display()
192→            );
193→        } else {
194→            fs::remove_dir_all(card_path).with_context(|| {
195→                format!("Failed to remove corrupt card: {}", card_path.display())
196→            })?;
197→            println!("Removed corrupt card: {}", card_path.display());
198→        }
199→        stats.corrupt_cards_removed += 1;
200→        stats.bytes_freed += size;

