 16→///
 17→/// Returns `None` for out-of-range or unset priority.
 18→fn dice_glyph(priority: Option<i64>) -> Option<char> {
 19→    match priority {
 20→        Some(1) => Some('⚀'),
 21→        Some(2) => Some('⚁'),
 22→        Some(3) => Some('⚂'),
 23→        Some(4) => Some('⚃'),
 24→        Some(5) => Some('⚄'),
 25→        Some(6) => Some('⚅'),
 26→        _ => None,
 27→    }
 28→}
