102→        }
103→
104→        if let Some(code) = card.exit_code {
105→            if card.state == "failed" {
106→                parts.push(format!("{}exit {}{}", color, code, RESET));
107→            }
108→        }
109→
110→        parts.join("  ")
111→    }
