113→    fn render_progress(&self, pct: u8, phase: Option<&str>, phase_frac: f32) -> String {
114→        let bar_width = 16;
115→        let filled = (pct as usize * bar_width) / 100;
116→        let empty = bar_width - filled;
117→
118→        let bar = format!("{}{} {}%", "█".repeat(filled), "░".repeat(empty), pct,);
119→
120→        let phase_str = if let Some(phase) = phase {
121→            format!("  {} {}", moon_glyph(phase_frac), phase)
122→        } else {
123→            String::new()
124→        };
125→
126→        format!("▌   {}{}", bar, phase_str)
127→    }
128→
129→    fn render_footer(&self, stats: &Stats) -> String {
130→        let mut parts = vec![format!("{} total", stats.total)];
131→
132→        if let Some(rate) = stats.success_rate_pct {
133→            parts.push(format!("{:.0}% success", rate));
134→        }
135→
136→        if let Some(avg) = stats.avg_duration_s {
137→            parts.push(format!("avg {}", format_duration(avg as u64)));
138→        }
139→
140→        let content = parts.join(" │ ");
141→        let w = self.width as usize;
142→        let footer = dithered_line(&content, w);
143→        format!("{}{}{}", DIM, footer, RESET)
144→    }
