 91→fn colorize_log_line(line: &str) -> String {
 92→    const R: &str = "\x1b[0m";
 93→    if line.contains("ERROR") || line.contains("error:") || line.contains("FAILED") {
 94→        return format!("\x1b[1;31m{}{}", line, R);
 95→    }
 96→    if line.contains("WARN") || line.contains("warning:") {
 97→        return format!("\x1b[33m{}{}", line, R);
 98→    }
 99→    if line.contains("INFO") {
100→        return format!("\x1b[36m{}{}", line, R);
101→    }
102→    if line.contains("DEBUG") || line.contains("TRACE") {
103→        return format!("\x1b[2m{}{}", line, R);
104→    }
105→    if line.contains("→ merged") || line.contains("-> merged") {
106→        return format!("\x1b[1;35m{}{}", line, R);
107→    }
108→    if line.contains("→ done") || line.contains("-> done") {
109→        return format!("\x1b[1;32m{}{}", line, R);
110→    }
111→    if line.contains("→ failed") || line.contains("-> failed") {
112→        return format!("\x1b[1;31m{}{}", line, R);
113→    }
114→    if line.contains("→ running") || line.contains("-> running") {
115→        return format!("\x1b[1;33m{}{}", line, R);
116→    }
117→    line.to_string()
118→}
119→
120→fn colorize_chunk(bytes: &[u8], is_tty: bool) -> String {
121→    let text = String::from_utf8_lossy(bytes);
122→    if !is_tty {
123→        return text.into_owned();
124→    }
125→    text.lines()
126→        .map(colorize_log_line)
127→        .collect::<Vec<_>>()
128→        .join("\n")
129→        + if text.ends_with('\n') { "\n" } else { "" }
130→}
