132→fn print_log_section(label: &str, path: &Path, is_tty: bool) -> anyhow::Result<()> {
133→    if !path.exists() {
134→        println!("=== {} (no file) ===", label);
135→        return Ok(());
136→    }
137→    let content = fs::read_to_string(path)?;
138→    if is_tty {
139→        println!("\x1b[1m=== {} ===\x1b[0m", label);
140→    } else {
141→        println!("=== {} ===", label);
142→    }
143→    if is_tty {
144→        for line in content.lines() {
145→            println!("{}", colorize_log_line(line));
146→        }
147→        if !content.ends_with('\n') && !content.is_empty() {
148→            // already printed trailing newline via println
149→        }
150→    } else {
151→        print!("{}", content);
152→        if !content.ends_with('\n') && !content.is_empty() {
153→            println!();
154→        }
155→    }
156→    Ok(())
157→}
