   213→    })?;
   214→    fs::create_dir_all(failed_path.join("logs"))?;
   215→    fs::create_dir_all(failed_path.join("output"))?;
   216→    let marker = format!("[{}] dispatcher rejected card: {}\n", Utc::now(), reason);
   217→    util::append_log_line(
   218→        &failed_path.join("logs").join("rejected.log"),
   219→        marker.trim_end(),
   220→    )?;
   221→    let _ = fs::write(failed_path.join("output").join("qa_report.md"), marker);
   222→    quicklook::render_card_thumbnail(&failed_path);
