    25→/// Summary statistics for cards in the workspace.
    26→pub struct CardStats {
    27→    pub total: usize,
    28→    pub by_state: HashMap<String, usize>,
    29→    pub avg_duration_s: Option<f64>,
    30→    pub success_rate_pct: Option<f64>,
    31→}
    32→
    33→/// Calculate statistics: count cards by state and compute average duration.
    34→pub fn calculate_stats(root: &Path) -> anyhow::Result<CardStats> {
    35→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
    36→    let mut by_state = HashMap::new();
    37→    let mut total = 0;
    38→    let mut durations = Vec::new();
    39→
    40→    for state in &states {
    41→        // Process root-level state directory
    42→        collect_state_stats(root, state, &mut by_state, &mut total, &mut durations)?;
    43→
    44→        // Process team-* directories
    45→        if let Ok(entries) = fs::read_dir(root) {
    46→            for entry in entries.flatten() {
    47→                let team_path = entry.path();
    48→                if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
    49→                    collect_state_stats(
    50→                        &team_path,
    51→                        state,
    52→                        &mut by_state,
    53→                        &mut total,
    54→                        &mut durations,
    55→                    )?;
    56→                }
    57→            }
    58→        }
    59→    }
    60→
    61→    let avg_duration_s = if durations.is_empty() {
    62→        None
    63→    } else {
    64→        Some(durations.iter().sum::<f64>() / durations.len() as f64)
    65→    };
    66→
    67→    let success_rate_pct = {
    68→        let done = by_state.get("done").copied().unwrap_or(0);
    69→        let failed = by_state.get("failed").copied().unwrap_or(0);
    70→        if done + failed > 0 {
    71→            Some((done as f64 / (done + failed) as f64) * 100.0)
    72→        } else {
    73→            None
    74→        }
    75→    };
    76→
    77→    Ok(CardStats {
    78→        total,
    79→        by_state,
    80→        avg_duration_s,
    81→        success_rate_pct,
    82→    })
    83→}
    84→
    85→fn collect_state_stats(
    86→    dir: &Path,
    87→    state: &str,
    88→    by_state: &mut HashMap<String, usize>,
    89→    total: &mut usize,
    90→    durations: &mut Vec<f64>,
    91→) -> anyhow::Result<()> {
    92→    let state_dir = dir.join(state);
    93→    if !state_dir.exists() {
    94→        return Ok(());
    95→    }
    96→
    97→    let Ok(entries) = fs::read_dir(&state_dir) else {
    98→        return Ok(());
    99→    };
   100→
   101→    for entry in entries.flatten() {
   102→        let path = entry.path();
   103→        if path.is_dir()
   104→            && path
   105→                .extension()
   106→                .is_some_and(|e| e == "bop" || e == "jobcard")
   107→        {
   108→            if let Ok(meta) = bop_core::read_meta(&path) {
   109→                *by_state.entry(state.to_string()).or_insert(0) += 1;
   110→                *total += 1;
   111→
   112→                // Collect duration from last run if available
   113→                if let Some(last_run) = meta.runs.last() {
   114→                    if let Some(dur) = last_run.duration_s {
   115→                        durations.push(dur as f64);
   116→                    }
   117→                }
   118→            }
   119→        }
   120→    }
   121→
   122→    Ok(())
   123→}
   124→
   125→/// Collect all cards for the given state filter into `(label, Vec<CardView>)` groups.
   126→fn collect_card_groups(
   127→    root: &Path,
   128→    state_filter: &str,
   129→) -> anyhow::Result<Vec<(String, Vec<render::CardView>)>> {
   130→    let states = resolve_states(state_filter);
   131→    let mut groups = Vec::new();
   132→
   133→    for state in &states {
   134→        // Collect root-level cards
   135→        let root_cards = collect_card_views(root, state)?;
   136→        if !root_cards.is_empty() {
   137→            groups.push((state.to_string(), root_cards));
   138→        }
   139→
   140→        // Collect team-* directory cards
   141→        if let Ok(entries) = fs::read_dir(root) {
   142→            let mut team_dirs: Vec<_> = entries
   143→                .flatten()
   144→                .filter(|e| {
   145→                    let name = e.file_name();
   146→                    let s = name.to_string_lossy();
   147→                    e.path().is_dir() && s.starts_with("team-")
   148→                })
   149→                .collect();
   150→            team_dirs.sort_by_key(|e| e.file_name());
   151→            for entry in team_dirs {
   152→                let team_name = entry.file_name().to_string_lossy().into_owned();
   153→                let team_cards = collect_card_views(&entry.path(), state)?;
   154→                if !team_cards.is_empty() {
   155→                    groups.push((format!("{}/{}", team_name, state), team_cards));
   156→                }
   157→            }
   158→        }
   159→    }
   160→
   161→    Ok(groups)
   162→}
   163→
   164→/// Collect [`CardView`] structs from a single state directory.
   165→fn collect_card_views(dir: &Path, state: &str) -> anyhow::Result<Vec<render::CardView>> {
   166→    let state_dir = dir.join(state);
   167→    if !state_dir.exists() {
   168→        return Ok(Vec::new());
   169→    }
   170→
   171→    let mut cards = Vec::new();
   172→    if let Ok(entries) = fs::read_dir(&state_dir) {
   173→        for entry in entries.flatten() {
   174→            let p = entry.path();
   175→            if p.is_dir() && p.extension().is_some_and(|e| e == "bop" || e == "jobcard") {
   176→                if let Ok(meta) = bop_core::read_meta(&p) {
   177→                    cards.push(render::from_meta(&meta, state));
   178→                }
   179→            }
   180→        }
   181→    }
   182→
   183→    Ok(cards)
   184→}
