    70→// ── Renderer trait ──────────────────────────────────────────────────────────
    71→
    72→/// Trait implemented by each terminal-level renderer (dumb through truecolor).
    73→pub trait CardRenderer {
    74→    /// Section header line for a state group (e.g. "=== RUNNING (2) ===").
    75→    fn render_section_header(&self, label: &str, count: usize) -> String;
    76→
    77→    /// One row per card in the listing.
    78→    fn render_card_row(&self, card: &CardView) -> String;
    79→
    80→    /// Progress bar with optional phase annotation.
    81→    fn render_progress(&self, pct: u8, phase: Option<&str>, phase_frac: f32) -> String;
    82→
    83→    /// Footer with summary statistics.
    84→    fn render_footer(&self, stats: &Stats) -> String;
    85→}
    86→
    87→// ── Conversion ──────────────────────────────────────────────────────────────
    88→
    89→/// Build a [`CardView`] from a [`Meta`] and its filesystem state directory name.
    90→///
    91→/// Fields not available from `Meta` (e.g. `phase_name`, `phase_frac`) are set
    92→/// to defaults — the caller may enrich them from AC plan data afterward.
    93→pub fn from_meta(meta: &Meta, state: &str) -> CardView {
    94→    let last_run = meta.runs.last();
    95→
    96→    CardView {
    97→        id: meta.id.clone(),
    98→        state: state.to_string(),
    99→        glyph: meta.glyph.clone(),
   100→        token: meta.token.clone(),
   101→        title: meta.title.clone().unwrap_or_else(|| meta.id.clone()),
   102→        stage: meta.stage.clone(),
   103→        priority: meta.priority,
   104→        progress: meta.progress.unwrap_or(0),
   105→        provider: last_run
   106→            .map(|r| r.provider.clone())
   107→            .filter(|s| !s.is_empty()),
   108→        elapsed_s: last_run.and_then(|r| r.duration_s),
   109→        phase_name: None,
   110→        phase_frac: 0.0,
   111→        failure_reason: meta.failure_reason.clone(),
   112→        exit_code: meta.exit_code,
   113→    }
   114→}
   115→
   116→// ── Board dispatch ──────────────────────────────────────────────────────────
   117→
   118→/// Render a full board to a `String`, selecting the renderer by [`TermLevel`].
   119→///
   120→/// `views` is a list of `(section_label, cards)` pairs — one per state group.
   121→/// Width is re-queried from `caps` on every call (never cached).
   122→pub fn render_board(caps: &TermCaps, views: &[(String, Vec<CardView>)], stats: &Stats) -> String {
   123→    let renderer: Box<dyn CardRenderer> = select_renderer(caps);
   124→    let mut out = String::new();
   125→
   126→    for (i, (label, cards)) in views.iter().enumerate() {
   127→        out.push_str(&renderer.render_section_header(label, cards.len()));
   128→        out.push('\n');
   129→
   130→        for card in cards {
   131→            out.push_str(&renderer.render_card_row(card));
   132→            out.push('\n');
   133→
   134→            if card.progress > 0 || card.phase_name.is_some() {
   135→                out.push_str(&renderer.render_progress(
   136→                    card.progress,
   137→                    card.phase_name.as_deref(),
   138→                    card.phase_frac,
   139→                ));
   140→                out.push('\n');
   141→            }
   142→        }
   143→
   144→        // Blank line between sections (but not after the last).
   145→        if i < views.len() - 1 {
   146→            out.push('\n');
   147→        }
   148→    }
   149→
   150→    out.push_str(&renderer.render_footer(stats));
   151→    out.push('\n');
   152→
   153→    out
   154→}
   155→
   156→/// Pick the concrete renderer for the detected terminal level.
   157→fn select_renderer(caps: &TermCaps) -> Box<dyn CardRenderer> {
   158→    match caps.level {
   159→        TermLevel::Dumb => Box::new(dumb::DumbRenderer),
   160→        TermLevel::Basic => Box::new(basic::BasicRenderer),
   161→        TermLevel::Extended => Box::new(extended::ExtendedRenderer { width: caps.width }),
   162→        TermLevel::Full => Box::new(full::FullRenderer { width: caps.width }),
   163→        TermLevel::TrueColor => Box::new(truecolor::TrueColorRenderer {
   164→            width: caps.width,
   165→            two_column: caps.two_column,
   166→        }),
   167→    }
   168→}
