    64→pub fn read_providers(cards_dir: &Path) -> anyhow::Result<ProvidersFile> {
    65→    let p = providers_path(cards_dir);
    66→    if !p.exists() {
    67→        return Ok(ProvidersFile::default());
    68→    }
    69→    let bytes = fs::read(p)?;
    70→    let pf: ProvidersFile = serde_json::from_slice(&bytes)?;
    71→    for (name, provider) in &pf.providers {
    72→        validate_provider(name, provider)?;
    73→    }
    74→    Ok(pf)
