    58→// ── KanbanColumn ────────────────────────────────────────────────────────────
    59→
    60→/// Column state names in display order.
    61→pub const COLUMN_STATES: &[&str] = &["pending", "running", "done", "failed", "merged"];
    62→
    63→/// One vertical column in the kanban board.
    64→///
    65→/// Each column corresponds to a card state directory. The `list_state`
    66→/// tracks the currently selected row within the column for ratatui's
    67→/// `StatefulWidget` rendering.
    68→#[derive(Debug, Clone)]
    69→pub struct KanbanColumn {
    70→    /// State name (e.g. "pending", "running").
    71→    pub state: String,
    72→    /// Cards currently in this state.
    73→    pub cards: Vec<CardView>,
    74→    /// Ratatui selection state for the list widget.
    75→    pub list_state: ListState,
    76→    /// WIP limit for this column (from config `max_concurrent` for "running").
    77→    pub wip_limit: Option<usize>,
    78→    /// Auto-collapsed when card count is 0.
    79→    pub collapsed: bool,
    80→}
    81→
    82→impl KanbanColumn {
    83→    /// Create a new column for the given state with cards.
    84→    fn new(state: &str, cards: Vec<CardView>, wip_limit: Option<usize>) -> Self {
    85→        let collapsed = cards.is_empty();
    86→        let mut list_state = ListState::default();
    87→        if !cards.is_empty() {
    88→            list_state.select(Some(0));
    89→        }
    90→        Self {
    91→            state: state.to_string(),
    92→            cards,
    93→            list_state,
    94→            wip_limit,
    95→            collapsed,
    96→        }
    97→    }
    98→
    99→    /// Returns true when the column is at or over its WIP limit.
   100→    pub fn is_at_wip_limit(&self) -> bool {
   101→        match self.wip_limit {
   102→            Some(limit) => self.cards.len() >= limit,
   103→            None => false,
   104→        }
   105→    }
   106→
   107→    /// WIP saturation fraction (0.0–1.0). Returns 0.0 when no limit is set.
   108→    pub fn wip_saturation(&self) -> f32 {
   109→        match self.wip_limit {
   110→            Some(limit) if limit > 0 => (self.cards.len() as f32 / limit as f32).min(1.0),
   111→            _ => 0.0,
   112→        }
   113→    }
   114→}
