213→/// Watch for filesystem changes and continuously redraw the card list.
214→/// This function sets up watchers on all state directories and redraws
215→/// the display whenever cards are added, removed, or modified.
216→pub async fn list_cards_watch(root: &Path, state_filter: &str) -> anyhow::Result<()> {
217→    // Singleton guard — only one watch instance per cards dir.
218→    // Uses mkdir-atomicity (same pattern as dispatcher lock).
219→    // Guard is held for the lifetime of the function; Drop removes the lock dir.
220→    let _watch_lock = lock::acquire_watch_lock(root).map_err(|e| {
221→        eprintln!("{}", e);
222→        e
223→    })?;
224→
225→    // Collect all state directories to watch
226→    let states = ["drafts", "pending", "running", "done", "failed", "merged"];
227→    let mut watch_dirs = Vec::new();
228→
229→    // Add root-level state directories
230→    for state in &states {
231→        let state_dir = root.join(state);
232→        if state_dir.exists() {
233→            watch_dirs.push(state_dir);
234→        }
235→    }
236→
237→    // Add team-* state directories
238→    if let Ok(entries) = fs::read_dir(root) {
239→        for entry in entries.flatten() {
240→            let team_path = entry.path();
241→            if team_path.is_dir() && entry.file_name().to_string_lossy().starts_with("team-") {
242→                for state in &states {
243→                    let state_dir = team_path.join(state);
244→                    if state_dir.exists() {
245→                        watch_dirs.push(state_dir);
246→                    }
247→                }
248→            }
249→        }
250→    }
251→
252→    // Set up filesystem watcher with 100ms debounce
253→    let (tx, mut rx) = tokio_mpsc::unbounded_channel();
254→    let watch_dirs_clone = watch_dirs.clone();
255→
256→    std::thread::spawn(move || {
257→        let (std_tx, std_rx) = std::sync::mpsc::channel();
258→        let mut debouncer = match new_debouncer(Duration::from_millis(100), std_tx) {
259→            Ok(d) => d,
260→            Err(e) => {
261→                eprintln!("[list_cards_watch] failed to create watcher: {}", e);
262→                return;
263→            }
264→        };
265→
266→        for watch_dir in &watch_dirs_clone {
267→            if let Err(e) = debouncer
268→                .watcher()
269→                .watch(watch_dir, notify::RecursiveMode::Recursive)
270→            {
271→                eprintln!(
272→                    "[list_cards_watch] failed to watch {}: {}",
273→                    watch_dir.display(),
274→                    e
275→                );
276→            }
277→        }
278→
279→        for res in std_rx {
280→            match res {
281→                Ok(events) => {
282→                    // Filter to only .bop directory events
283→                    let relevant = events.iter().any(|e| {
284→                        e.path.extension().and_then(|s| s.to_str()) == Some("bop")
285→                            && matches!(
286→                                e.kind,
287→                                DebouncedEventKind::Any | DebouncedEventKind::AnyContinuous
288→                            )
289→                    });
290→                    if relevant {
291→                        let _ = tx.send(());
292→                    }
293→                }
294→                Err(e) => {
295→                    eprintln!("[list_cards_watch] watch error: {}", e);
296→                }
297→            }
298→        }
299→    });
300→
301→    // Track previous state for minimal redraw
302→    let mut prev_stats;
303→    let mut prev_line_count;
304→
305→    // Initial render
306→    {
307→        let caps = TermCaps::detect();
308→        print_clock_header();
309→
310→        let current_stats = calculate_stats(root)?;
311→        let groups = collect_card_groups(root, state_filter)?;
312→        let rstats = stats_to_render_stats(&current_stats);
313→        let output = render::render_board(&caps, &groups, &rstats);
314→
315→        // Count lines for cursor-up positioning (1 for clock header + rendered output)
316→        let line_count = 1 + output.lines().count();
317→        print!("{}", output);
318→        io::stdout().flush().ok();
319→
320→        prev_line_count = line_count;
321→        prev_stats = Some(current_stats);
322→    }
323→
324→    loop {
325→        tokio::select! {
326→            _ = tokio::signal::ctrl_c() => {
327→                // Clean shutdown on Ctrl-C
328→                // Move cursor down past last output to avoid overwriting
329→                if prev_line_count > 0 {
330→                    print!("\x1b[{}B", 1);
331→                    io::stdout().flush().ok();
332→                }
333→                println!("\nShutting down...");
334→                return Ok(());
335→            }
336→            event = rx.recv() => {
337→                if event.is_none() {
338→                    // Channel closed, watcher thread exited
339→                    return Ok(());
340→                }
341→
342→                // Calculate current stats
343→                let current_stats = match calculate_stats(root) {
344→                    Ok(stats) => stats,
345→                    Err(e) => {
346→                        eprintln!("[list_cards_watch] error calculating stats: {}", e);
347→                        continue;
348→                    }
349→                };
350→
351→                // Only redraw if stats changed (minimal redraw to avoid flicker)
352→                let stats_changed = prev_stats
353→                    .as_ref()
354→                    .map(|prev| {
355→                        prev.total != current_stats.total || prev.by_state != current_stats.by_state
356→                    })
357→                    .unwrap_or(true);
358→
359→                if stats_changed {
360→                    // Move cursor up to previous position if not first render
361→                    if prev_line_count > 0 {
362→                        print!("\x1b[{}A", prev_line_count);
363→                        io::stdout().flush().ok();
364→                    }
365→
366→                    // Re-detect terminal capabilities on every redraw (never cache)
367→                    let caps = TermCaps::detect();
368→                    print_clock_header();
369→
370→                    let groups = match collect_card_groups(root, state_filter) {
371→                        Ok(g) => g,
372→                        Err(e) => {
373→                            eprintln!("[list_cards_watch] error collecting cards: {}", e);
374→                            prev_stats = Some(current_stats);
375→                            continue;
376→                        }
377→                    };
378→                    let rstats = stats_to_render_stats(&current_stats);
379→                    let output = render::render_board(&caps, &groups, &rstats);
380→
381→                    // Count lines for cursor-up positioning (1 for clock header + rendered output)
382→                    let line_count = 1 + output.lines().count();
383→                    print!("{}", output);
384→                    io::stdout().flush().ok();
385→
386→                    prev_line_count = line_count;
387→                    prev_stats = Some(current_stats);
388→                }
389→            }
