35→        match event {
36→            AppEvent::Key(key) => {
37→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
38→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
39→                    && key.code == KeyCode::Char('c');
