115→            .style(Style::default().fg(Color::White))
116→            .block(Block::bordered().title(" kanban "));
117→        frame.render_widget(body, zones[1]);
118→
119→        // ── Footer (1 row) ─────────────────────────────────────────────
120→        let footer = Paragraph::new(
121→            "[h/l]col [j/k]card [↵]actions [/]filter [n]new [q]quit",
122→        )
