    60→/// Column state names in display order.
    61→pub const COLUMN_STATES: &[&str] = &["pending", "running", "done", "failed", "merged"];
    62→
    63→/// One vertical column in the kanban board.
    64→///
    65→/// Each column corresponds to a card state directory. The `list_state`
    66→/// tracks the currently selected row within the column for ratatui's
    67→/// `StatefulWidget` rendering.
    68→#[derive(Debug, Clone)]
    69→pub struct KanbanColumn {
    70→    /// State name (e.g. "pending", "running").
    71→    pub state: String,
    72→    /// Cards currently in this state.
    73→    pub cards: Vec<CardView>,
    74→    /// Ratatui selection state for the list widget.
    75→    pub list_state: ListState,
    76→    /// WIP limit for this column (from config `max_concurrent` for "running").
    77→    pub wip_limit: Option<usize>,
