   150→    /// `list.rs::collect_card_views`. Reads `max_concurrent` from the
   151→    /// bop-core config for the "running" column's WIP limit.
   152→    pub fn new(cards_root: &Path) -> anyhow::Result<Self> {
   153→        let columns = build_columns(cards_root);
   154→
   155→        // Focus the first non-collapsed column, or 0 if all are collapsed.
   156→        let col_focus = columns
   157→            .iter()
   158→            .position(|c| !c.collapsed)
   159→            .unwrap_or(0);
   160→
   161→        Ok(App {
   162→            columns,
   163→            col_focus,
   164→            filter: None,
   165→            mode: Mode::Normal,
   166→            log_buf: VecDeque::with_capacity(LOG_BUF_CAPACITY),
   167→            throughput: VecDeque::from(vec![0u8; THROUGHPUT_SAMPLES]),
   168→            cards_root: cards_root.to_path_buf(),
   169→        })
   170→    }
