 16→/// Launch the interactive TUI kanban board.
 17→///
 18→/// Sets up the terminal guard (alternate screen + raw mode), initialises
 19→/// the application state, spawns background event producers, and enters
 20→/// the main event loop. On exit (q or Ctrl-C), the `TerminalGuard`
 21→/// restores the terminal via its `Drop` impl.
 22→pub async fn run_ui(root: &Path) -> anyhow::Result<()> {
 23→    // Initialise application state from the filesystem.
 24→    let mut app = App::new(root)?;
 25→
 26→    // Enter alternate screen + raw mode (restored on Drop).
 27→    let _guard = TerminalGuard::new()?;
 28→
 29→    // Create ratatui terminal with crossterm backend.
 30→    let backend = ratatui::backend::CrosstermBackend::new(io::stdout());
 31→    let mut terminal = Terminal::new(backend)?;
 32→
 33→    // Spawn background tasks: crossterm reader, tick timer, fs watcher.
 34→    let mut events = EventLoop::new(root);
 35→
 36→    // ── Initial render ─────────────────────────────────────────────────
 37→    draw(&mut terminal, &app)?;
 38→
 39→    // ── Main event loop ────────────────────────────────────────────────
 40→    loop {
 41→        let Some(event) = events.next().await else {
 42→            break; // all senders dropped — clean shutdown
 43→        };
 44→
 45→        match event {
 46→            AppEvent::Key(key) => {
 47→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
 48→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
 49→                    && key.code == KeyCode::Char('c');
 50→                let quit = app.mode == Mode::Normal && key.code == KeyCode::Char('q');
 51→
 52→                if ctrl_c || quit {
 53→                    break;
 54→                }
 55→
 56→                // Remaining key handling will be wired in subtask 2-2 (input.rs).
 57→            }
 58→            AppEvent::Resize(_w, _h) => {
 59→                // Resize handling will be implemented in subtask 6-4.
 60→            }
 61→            AppEvent::Tick => {
 62→                // Clock + sparkline updates will be wired in subtask 3-1.
 63→            }
 64→            AppEvent::Cards(columns) => {
 65→                app.refresh_columns(columns);
 66→            }
 67→            AppEvent::LogLine(line) => {
 68→                app.push_log_line(line);
 69→            }
 70→        }
 71→
 72→        // Re-render after every event.
 73→        draw(&mut terminal, &app)?;
 74→    }
 75→
 76→    // _guard drops here → restores alternate screen + raw mode.
 77→    Ok(())
 78→}
