 17→/// Launch the interactive TUI kanban board.
 18→///
 19→/// Sets up the terminal guard (alternate screen + raw mode), initialises
 20→/// the application state, spawns background event producers, and enters
 21→/// the main event loop. On exit (q or Ctrl-C), the `TerminalGuard`
 22→/// restores the terminal via its `Drop` impl.
 23→pub async fn run_ui(root: &Path) -> anyhow::Result<()> {
 24→    // Initialise application state from the filesystem.
 25→    let mut app = App::new(root)?;
 26→
 27→    // Enter alternate screen + raw mode (restored on Drop).
 28→    let _guard = TerminalGuard::new()?;
 29→
 30→    // Create ratatui terminal with crossterm backend.
 31→    let backend = ratatui::backend::CrosstermBackend::new(io::stdout());
 32→    let mut terminal = Terminal::new(backend)?;
 33→
 34→    // Spawn background tasks: crossterm reader, tick timer, fs watcher.
 35→    let mut events = EventLoop::new(root);
 36→
 37→    // ── Initial render ─────────────────────────────────────────────────
 38→    draw(&mut terminal, &app)?;
 39→
 40→    // ── Main event loop ────────────────────────────────────────────────
 41→    loop {
 42→        let Some(event) = events.next().await else {
 43→            break; // all senders dropped — clean shutdown
 44→        };
 45→
 46→        match event {
 47→            AppEvent::Key(key) => {
 48→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
 49→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
 50→                    && key.code == KeyCode::Char('c');
 51→                let quit = app.mode == Mode::Normal && key.code == KeyCode::Char('q');
 52→
 53→                if ctrl_c || quit {
 54→                    break;
 55→                }
 56→
 57→                // Remaining key handling will be wired in subtask 2-2 (input.rs).
 58→            }
 59→            AppEvent::Resize(_w, _h) => {
 60→                // Resize handling will be implemented in subtask 6-4.
 61→            }
 62→            AppEvent::Tick => {
 63→                // Clock + sparkline updates will be wired in subtask 3-1.
 64→            }
 65→            AppEvent::Cards(columns) => {
 66→                app.refresh_columns(columns);
 67→            }
 68→            AppEvent::LogLine(line) => {
 69→                app.push_log_line(line);
 70→            }
 71→        }
 72→
 73→        // Re-render after every event.
 74→        draw(&mut terminal, &app)?;
 75→    }
 76→
 77→    // _guard drops here → restores alternate screen + raw mode.
 78→    Ok(())
 79→}
