 81→/// Render the three-zone layout: header (2 rows), body (remaining), footer (1 row).
 82→///
 83→/// Uses ratatui's `Layout::vertical` to divide the terminal into the
 84→/// k9s-style three-zone layout. Placeholder widgets for now — real
 85→/// widgets will be wired in subsequent subtasks (header in 3-1, kanban
 86→/// body in 2-1, footer in 3-2).
 87→fn draw(
 88→    terminal: &mut Terminal<ratatui::backend::CrosstermBackend<Stdout>>,
 89→    app: &App,
 90→) -> anyhow::Result<()> {
 91→    terminal.draw(|frame| {
 92→        let area = frame.area();
 93→
 94→        // Three-zone layout: header (2), body (fill), footer (1).
 95→        let zones = Layout::vertical([
 96→            Constraint::Length(2),
 97→            Constraint::Min(0),
 98→            Constraint::Length(1),
 99→        ])
100→        .split(area);
101→
102→        // ── Header (2 rows) ────────────────────────────────────────────
103→        let header = Paragraph::new("bop · --:--:-- · placeholder header")
104→            .style(Style::default().fg(Color::Cyan))
105→            .block(Block::default());
106→        frame.render_widget(header, zones[0]);
107→
108→        // ── Body (remaining space) ─────────────────────────────────────
109→        let card_count = app.total_cards();
110→        let body_text = format!(
111→            "kanban body — {} card{} loaded",
112→            card_count,
113→            if card_count == 1 { "" } else { "s" }
114→        );
115→        let body = Paragraph::new(body_text)
116→            .style(Style::default().fg(Color::White))
117→            .block(Block::bordered().title(" kanban "));
118→        frame.render_widget(body, zones[1]);
119→
120→        // ── Footer (1 row) ─────────────────────────────────────────────
121→        let footer = Paragraph::new(
122→            "[h/l]col [j/k]card [↵]actions [/]filter [n]new [q]quit",
123→        )
124→        .style(Style::default().fg(Color::DarkGray));
125→        frame.render_widget(footer, zones[2]);
126→    })?;
127→
128→    Ok(())
129→}
