    88→// ── Column title ─────────────────────────────────────────────────────────────
    89→
    90→/// Build the column title `Line` with state glyph, name, and count.
    91→///
    92→/// Running columns with a WIP limit show `⚙ RUNNING (N/M)`, with color
    93→/// changing at 75% (amber) and 100% (red) saturation.
    94→fn column_title(col: &KanbanColumn) -> Line<'static> {
    95→    let glyph = state_glyph(&col.state);
    96→    let name = col.state.to_uppercase();
    97→    let count = col.cards.len();
    98→
    99→    let title_text = if col.state == "running" {
   100→        if let Some(limit) = col.wip_limit {
   101→            format!(" {} {} ({}/{}) ", glyph, name, count, limit)
   102→        } else {
   103→            format!(" {} {} ({}) ", glyph, name, count)
   104→        }
   105→    } else {
   106→        format!(" {} {} ({}) ", glyph, name, count)
   107→    };
   108→
   109→    let color = title_color(col);
   110→    Line::from(Span::styled(
   111→        title_text,
   112→        Style::default().fg(color).add_modifier(Modifier::BOLD),
   113→    ))
   114→}
   115→
   116→/// Determine title color based on state and WIP saturation.
   117→///
   118→/// Running column with WIP limit: amber at ≥75%, red at 100%.
   119→/// All other columns use their default state color.
   120→fn title_color(col: &KanbanColumn) -> Color {
   121→    if col.state == "running" && col.wip_limit.is_some() {
   122→        let sat = col.wip_saturation();
   123→        if sat >= 1.0 {
   124→            Color::Red
   125→        } else if sat >= 0.75 {
   126→            Color::Yellow
   127→        } else {
   128→            state_ratatui_color(&col.state)
   129→        }
   130→    } else {
   131→        state_ratatui_color(&col.state)
   132→    }
   133→}
   134→
   135→/// Determine border color for a column.
   136→///
   137→/// Priority: running at 100% WIP → red (even if focused), focused → yellow,
   138→/// running ≥75% → amber, default → dark gray.
   139→fn border_color(col: &KanbanColumn, is_focused: bool) -> Color {
   140→    if col.state == "running" && col.wip_limit.is_some() {
   141→        let sat = col.wip_saturation();
   142→        if sat >= 1.0 {
   143→            return Color::Red;
   144→        } else if sat >= 0.75 {
   145→            return Color::Yellow;
   146→        }
   147→    }
   148→
   149→    if is_focused {
   150→        Color::Yellow
   151→    } else {
   152→        Color::DarkGray
   153→    }
   154→}
