 19→/// Launch the interactive TUI kanban board.
 20→///
 21→/// Sets up the terminal guard (alternate screen + raw mode), initialises
 22→/// the application state, spawns background event producers, and enters
 23→/// the main event loop. On exit (q or Ctrl-C), the `TerminalGuard`
 24→/// restores the terminal via its `Drop` impl.
 25→pub async fn run_ui(root: &Path) -> anyhow::Result<()> {
 26→    // Initialise application state from the filesystem.
 27→    let mut app = App::new(root)?;
 28→
 29→    // Enter alternate screen + raw mode (restored on Drop).
 30→    let _guard = TerminalGuard::new()?;
 31→
 32→    // Create ratatui terminal with crossterm backend.
 33→    let backend = ratatui::backend::CrosstermBackend::new(io::stdout());
 34→    let mut terminal = Terminal::new(backend)?;
 35→
 36→    // Spawn background tasks: crossterm reader, tick timer, fs watcher.
 37→    let mut events = EventLoop::new(root);
 38→
 39→    // ── Initial render ─────────────────────────────────────────────────
 40→    draw(&mut terminal, &app)?;
 41→
 42→    // ── Main event loop ────────────────────────────────────────────────
 43→    loop {
 44→        let Some(event) = events.next().await else {
 45→            break; // all senders dropped — clean shutdown
 46→        };
 47→
 48→        match event {
 49→            AppEvent::Key(key) => {
 50→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
 51→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
 52→                    && key.code == KeyCode::Char('c');
 53→                let quit = app.mode == Mode::Normal && key.code == KeyCode::Char('q');
 54→
 55→                if ctrl_c || quit {
 56→                    break;
 57→                }
 58→
 59→                // Dispatch remaining keys to mode-specific handler.
 60→                input::handle_key(&mut app, key);
 61→            }
 62→            AppEvent::Resize(_w, _h) => {
 63→                // Resize handling will be implemented in subtask 6-4.
 64→            }
 65→            AppEvent::Tick => {
 66→                // Clock + sparkline updates will be wired in subtask 3-1.
 67→            }
 68→            AppEvent::Cards(columns) => {
 69→                app.refresh_columns(columns);
 70→            }
 71→            AppEvent::LogLine(line) => {
 72→                app.push_log_line(line);
 73→            }
 74→        }
 75→
 76→        // Re-render after every event.
 77→        draw(&mut terminal, &app)?;
