     1→/// TUI application state and event types.
     2→///
     3→/// Defines the core data model for the kanban TUI: columns, card views,
     4→/// navigation state, and the event enum that unifies keyboard input,
     5→/// filesystem changes, and timer ticks into a single async stream.
     6→use std::collections::VecDeque;
     7→use std::fs;
     8→use std::path::{Path, PathBuf};
     9→
    10→use crossterm::event::KeyEvent;
    11→use ratatui::widgets::ListState;
    12→
    13→use crate::render::CardView;
    14→
    15→// ── Events ──────────────────────────────────────────────────────────────────
    16→
    17→/// Unified event type for the TUI event loop.
    18→///
    19→/// Background tasks (fs watcher, log reader, timer) send these through
    20→/// `tokio::sync::mpsc::unbounded_channel`. The UI loop processes them
    21→/// sequentially — never blocking the render thread.
    22→#[derive(Debug)]
    23→pub enum AppEvent {
    24→    /// Keyboard input from crossterm.
    25→    Key(KeyEvent),
    26→    /// Terminal resize (cols, rows).
    27→    Resize(u16, u16),
    28→    /// 250ms heartbeat for clock, sparkline, and animation updates.
    29→    Tick,
    30→    /// Filesystem watcher detected card changes — full refresh payload.
    31→    Cards(Vec<KanbanColumn>),
    32→    /// New complete line from the selected card's log tail.
    33→    LogLine(String),
    34→}
    35→
    36→// ── Mode ────────────────────────────────────────────────────────────────────
    37→
    38→/// Current interaction mode. Determines which keybindings are active
    39→/// and which overlay (if any) is drawn on top of the kanban body.
    40→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    41→pub enum Mode {
    42→    /// Default: column/card navigation, action keys active.
    43→    Normal,
    44→    /// `/` filter active — keystrokes go to nucleo query input.
    45→    Filter,
    46→    /// Enter key opened the action popup overlay.
    47→    ActionPopup,
    48→    /// `d` opened the card detail overlay.
    49→    Detail,
    50→    /// Log tail overlay — full-height scrollable log view.
    51→    LogTail,
    52→    /// `n` inline card creation prompt.
    53→    NewCard,
    54→    /// `!` subshell — TUI suspended, shell active in card worktree.
    55→    Subshell,
    56→}
    57→
    58→// ── KanbanColumn ────────────────────────────────────────────────────────────
    59→
    60→/// Column state names in display order.
    61→pub const COLUMN_STATES: &[&str] = &["pending", "running", "done", "failed", "merged"];
    62→
    63→/// One vertical column in the kanban board.
    64→///
    65→/// Each column corresponds to a card state directory. The `list_state`
    66→/// tracks the currently selected row within the column for ratatui's
    67→/// `StatefulWidget` rendering.
    68→#[derive(Debug, Clone)]
    69→pub struct KanbanColumn {
    70→    /// State name (e.g. "pending", "running").
    71→    pub state: String,
    72→    /// Cards currently in this state.
    73→    pub cards: Vec<CardView>,
    74→    /// Ratatui selection state for the list widget.
    75→    pub list_state: ListState,
    76→    /// WIP limit for this column (from config `max_concurrent` for "running").
    77→    pub wip_limit: Option<usize>,
    78→    /// Auto-collapsed when card count is 0.
    79→    pub collapsed: bool,
    80→}
    81→
    82→impl KanbanColumn {
    83→    /// Create a new column for the given state with cards.
    84→    pub(crate) fn new(state: &str, cards: Vec<CardView>, wip_limit: Option<usize>) -> Self {
    85→        let collapsed = cards.is_empty();
    86→        let mut list_state = ListState::default();
    87→        if !cards.is_empty() {
    88→            list_state.select(Some(0));
    89→        }
    90→        Self {
    91→            state: state.to_string(),
    92→            cards,
    93→            list_state,
    94→            wip_limit,
    95→            collapsed,
    96→        }
    97→    }
    98→
    99→    /// Returns true when the column is at or over its WIP limit.
   100→    pub fn is_at_wip_limit(&self) -> bool {
   101→        match self.wip_limit {
   102→            Some(limit) => self.cards.len() >= limit,
   103→            None => false,
   104→        }
   105→    }
   106→
   107→    /// WIP saturation fraction (0.0–1.0). Returns 0.0 when no limit is set.
   108→    pub fn wip_saturation(&self) -> f32 {
   109→        match self.wip_limit {
   110→            Some(limit) if limit > 0 => (self.cards.len() as f32 / limit as f32).min(1.0),
   111→            _ => 0.0,
   112→        }
   113→    }
   114→}
   115→
   116→// ── App ─────────────────────────────────────────────────────────────────────
   117→
   118→/// Top-level TUI application state.
   119→///
   120→/// Holds all columns, focus indices, mode, log buffer, and throughput
   121→/// sparkline data. The render layer reads this immutably; event handlers
   122→/// mutate it.
   123→pub struct App {
   124→    /// Kanban columns in display order (pending → running → done → failed → merged).
   125→    pub columns: Vec<KanbanColumn>,
   126→    /// Index into `columns` for the currently focused column.
   127→    pub col_focus: usize,
   128→    /// Active nucleo filter query (None = no filter).
   129→    pub filter: Option<String>,
   130→    /// Current interaction mode.
   131→    pub mode: Mode,
   132→    /// Circular buffer of recent log lines (last 200) from the selected card.
   133→    pub log_buf: VecDeque<String>,
   134→    /// Throughput sparkline samples (last 8 values, cards/hr).
   135→    pub throughput: VecDeque<u8>,
   136→    /// Root path of the .cards directory.
   137→    pub cards_root: PathBuf,
   138→}
   139→
   140→/// Maximum number of log lines retained in the circular buffer.
   141→const LOG_BUF_CAPACITY: usize = 200;
   142→
   143→/// Number of throughput sparkline samples.
   144→const THROUGHPUT_SAMPLES: usize = 8;
   145→
   146→impl App {
   147→    /// Create a new App by scanning the filesystem for cards.
   148→    ///
   149→    /// Reads cards from the `.cards` directory using the same pattern as
   150→    /// `list.rs::collect_card_views`. Reads `max_concurrent` from the
   151→    /// bop-core config for the "running" column's WIP limit.
   152→    pub fn new(cards_root: &Path) -> anyhow::Result<Self> {
   153→        let columns = build_columns(cards_root);
   154→
   155→        // Focus the first non-collapsed column, or 0 if all are collapsed.
   156→        let col_focus = columns
   157→            .iter()
   158→            .position(|c| !c.collapsed)
   159→            .unwrap_or(0);
   160→
   161→        Ok(App {
   162→            columns,
   163→            col_focus,
   164→            filter: None,
   165→            mode: Mode::Normal,
   166→            log_buf: VecDeque::with_capacity(LOG_BUF_CAPACITY),
   167→            throughput: VecDeque::from(vec![0u8; THROUGHPUT_SAMPLES]),
   168→            cards_root: cards_root.to_path_buf(),
   169→        })
   170→    }
   171→
   172→    /// Return the currently focused column, if any.
   173→    pub fn focused_column(&self) -> Option<&KanbanColumn> {
   174→        self.columns.get(self.col_focus)
   175→    }
   176→
   177→    /// Return a mutable reference to the currently focused column.
   178→    pub fn focused_column_mut(&mut self) -> Option<&mut KanbanColumn> {
   179→        self.columns.get_mut(self.col_focus)
   180→    }
   181→
   182→    /// Return the currently selected card in the focused column.
   183→    pub fn selected_card(&self) -> Option<&CardView> {
   184→        let col = self.focused_column()?;
   185→        let idx = col.list_state.selected()?;
   186→        col.cards.get(idx)
   187→    }
   188→
   189→    /// Total card count across all columns.
   190→    pub fn total_cards(&self) -> usize {
   191→        self.columns.iter().map(|c| c.cards.len()).sum()
   192→    }
   193→
   194→    /// Push a log line into the circular buffer, evicting the oldest if full.
   195→    pub fn push_log_line(&mut self, line: String) {
   196→        if self.log_buf.len() >= LOG_BUF_CAPACITY {
   197→            self.log_buf.pop_front();
   198→        }
   199→        self.log_buf.push_back(line);
   200→    }
   201→
   202→    /// Push a throughput sample, evicting the oldest.
   203→    pub fn push_throughput(&mut self, value: u8) {
   204→        if self.throughput.len() >= THROUGHPUT_SAMPLES {
   205→            self.throughput.pop_front();
   206→        }
   207→        self.throughput.push_back(value);
   208→    }
   209→
   210→    /// Replace all column data (e.g. after a filesystem change notification).
   211→    ///
   212→    /// Preserves the selected row index in each column where possible:
   213→    /// if the old column had a selection at index N and the new column has
   214→    /// at least N+1 cards, the selection is restored. Otherwise, the
   215→    /// selection is clamped to the last card (or cleared if empty).
   216→    pub fn refresh_columns(&mut self, mut new_columns: Vec<KanbanColumn>) {
   217→        // Preserve selection state where possible.
   218→        for new_col in &mut new_columns {
   219→            if let Some(old_col) = self.columns.iter().find(|c| c.state == new_col.state) {
   220→                if let Some(old_idx) = old_col.list_state.selected() {
   221→                    if new_col.cards.is_empty() {
   222→                        new_col.list_state.select(None);
   223→                    } else {
   224→                        let clamped = old_idx.min(new_col.cards.len() - 1);
   225→                        new_col.list_state.select(Some(clamped));
   226→                    }
   227→                }
   228→            }
   229→        }
   230→        self.columns = new_columns;
   231→
   232→        // Update collapsed state for all columns.
   233→        self.update_collapse();
   234→
   235→        // Clamp col_focus if columns shrunk (shouldn't happen with fixed states).
   236→        if self.col_focus >= self.columns.len() {
   237→            self.col_focus = self.columns.len().saturating_sub(1);
   238→        }

