   145→pub fn select_provider(
   146→    cards_dir: &Path,
   147→    meta: Option<&mut Meta>,
   148→    stage: &str,
   149→) -> anyhow::Result<Option<ProviderSelection>> {
   150→    let pf = read_providers(cards_dir)?;
   151→    let now = Utc::now().timestamp();
   152→
   153→    let avoid_provider = if stage == "qa" {
   154→        meta.as_ref()
   155→            .and_then(|m| m.stages.get("implement"))
   156→            .and_then(|r| r.provider.clone())
   157→    } else {
   158→        None
   159→    };
   160→
   161→    let chain: Vec<String> = match meta {
   162→        Some(m) => {
   163→            if m.provider_chain.is_empty() {
   164→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   165→            }
   166→            m.provider_chain.clone()
   167→        }
   168→        None => vec!["mock".to_string(), "mock2".to_string()],
   169→    };
   170→
   171→    let mut fallback: Option<ProviderSelection> = None;
   172→    for name in chain {
   173→        let Some(p) = pf.providers.get(&name) else {
   174→            continue;
   175→        };
   176→        if let Some(until) = p.cooldown_until_epoch_s {
   177→            if until > now {
   178→                continue;
   179→            }
   180→        }
   181→
   182→        if let Some(ref avoid) = avoid_provider {
   183→            if &name == avoid {
   184→                if fallback.is_none() {
   185→                    fallback = Some((
   186→                        name,
   187→                        p.command.clone(),
   188→                        p.rate_limit_exit,
   189→                        p.env.clone(),
   190→                        p.model.clone(),
   191→                    ));
   192→                }
   193→                continue;
   194→            }
   195→        }
   196→
   197→        return Ok(Some((
   198→            name,
   199→            p.command.clone(),
   200→            p.rate_limit_exit,
   201→            p.env.clone(),
   202→            p.model.clone(),
   203→        )));
   204→    }
   205→
   206→    Ok(fallback)
   207→}
   208→
   209→pub fn set_provider_cooldown(
   210→    cards_dir: &Path,
   211→    provider: &str,
   212→    cooldown_s: i64,
   213→) -> anyhow::Result<()> {
   214→    let mut pf = read_providers(cards_dir)?;
   215→    let now = Utc::now().timestamp();
   216→    if let Some(p) = pf.providers.get_mut(provider) {
   217→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
   218→    }
   219→    write_providers(cards_dir, &pf)?;
   220→    Ok(())
   221→}
