   156→// ── Card list items ──────────────────────────────────────────────────────────
   157→
   158→/// Build a `ListItem` for a single card.
   159→///
   160→/// Running cards get two lines (row + progress bar with phase name).
   161→/// All other states get a single line showing marker, title, provider,
   162→/// and elapsed time.
   163→fn card_to_list_item(card: &CardView) -> ListItem<'static> {
   164→    let color = state_ratatui_color(&card.state);
   165→
   166→    // Use BMP-safe token if available, then glyph, then state marker.
   167→    let display_marker = card
   168→        .token
