   170→        .or(card.glyph.as_deref())
   171→        .unwrap_or(card_marker(&card.state));
   172→
   173→    // First line: marker + title + provider + elapsed.
   174→    let mut spans = vec![
   175→        Span::styled(
   176→            format!("{} ", display_marker),
   177→            Style::default().fg(color),
   178→        ),
   179→        Span::styled(card.title.clone(), Style::default().fg(Color::White)),
   180→    ];
   181→
   182→    if let Some(ref provider) = card.provider {
   183→        spans.push(Span::raw("  "));
   184→        spans.push(Span::styled(
   185→            provider.clone(),
   186→            Style::default().fg(Color::DarkGray),
   187→        ));
   188→    }
   189→
   190→    if let Some(elapsed) = card.elapsed_s {
   191→        spans.push(Span::raw("  "));
   192→        spans.push(Span::styled(
   193→            format_duration(elapsed),
   194→            Style::default().fg(Color::DarkGray),
   195→        ));
   196→    }
   197→
   198→    if let Some(code) = card.exit_code {
   199→        if card.state == "failed" {
   200→            spans.push(Span::raw("  "));
   201→            spans.push(Span::styled(
   202→                format!("exit {}", code),
   203→                Style::default().fg(color),
   204→            ));
   205→        }
   206→    }
   207→
   208→    let first_line = Line::from(spans);
   209→
   210→    // Running cards with progress get a second line.
   211→    if card.state == "running" && (card.progress > 0 || card.phase_name.is_some()) {
