    22→// ── Glyph helpers ────────────────────────────────────────────────────────────
    23→
    24→/// State glyph for column headers and collapsed dividers.
    25→///
    26→/// Matches the spec's visual language: `·` pending, `⚙` running,
    27→/// `✓` done, `✗` failed, `~` merged.
    28→fn state_glyph(state: &str) -> &'static str {
    29→    match state {
    30→        "pending" => "·",
    31→        "running" => "⚙",
    32→        "done" => "✓",
    33→        "failed" => "✗",
    34→        "merged" => "~",
    35→        _ => "?",
    36→    }
    37→}
    38→
    39→/// Card marker glyph for list rows (matches render/full.rs pattern).
    40→fn card_marker(state: &str) -> &'static str {
    41→    match state {
    42→        "running" => "▶",
    43→        "done" | "merged" => "✓",
    44→        "failed" => "✗",
    45→        _ => "·",
    46→    }
    47→}
