    56→        "running" => Color::Rgb(0xB8, 0x69, 0x0F),
    57→        "done" => Color::Rgb(0x1E, 0x8A, 0x45),
    58→        "failed" => Color::Rgb(0xC4, 0x30, 0x30),
    59→        "merged" => Color::Rgb(0x6B, 0x3D, 0xB8),
    60→        _ => Color::Gray,
    61→    }
    62→}
    63→
    64→/// Moon-quarter glyph for phase progress (matches render/full.rs).
    65→///
    66→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    67→fn moon_glyph(frac: f32) -> char {
    68→    if frac < 0.25 {
    69→        '◔'
    70→    } else if frac < 0.50 {
    71→        '◑'
    72→    } else if frac < 0.75 {
