    79→enum Direction {
    80→    Left,
    81→    Right,
    82→    Up,
    83→    Down,
    84→}
    85→
    86→/// Move column focus left or right, wrapping at boundaries.
    87→///
    88→/// Skips collapsed (empty) columns — if all columns are collapsed,
    89→/// focus stays at index 0.
    90→fn move_col_focus(app: &mut App, dir: Direction) {
    91→    let len = app.columns.len();
    92→    if len == 0 {
    93→        return;
    94→    }
    95→
    96→    let step: isize = match dir {
    97→        Direction::Left => -1,
    98→        Direction::Right => 1,
    99→        _ => return,
   100→    };
   101→
   102→    // Try up to `len` positions to find a non-collapsed column.
   103→    let mut candidate = app.col_focus as isize;
   104→    for _ in 0..len {
   105→        candidate = (candidate + step).rem_euclid(len as isize);
   106→        let idx = candidate as usize;
   107→        if !app.columns[idx].collapsed {
   108→            app.col_focus = idx;
   109→            return;
   110→        }
   111→    }
   112→
   113→    // All columns collapsed — stay where we are.
   114→}
