 84→/// Render the three-zone layout: header (2 rows), body (remaining), footer (1 row).
 85→///
 86→/// Uses ratatui's `Layout::vertical` to divide the terminal into the
 87→/// k9s-style three-zone layout. The body zone renders the kanban board
 88→/// via [`render_kanban`]; header and footer are placeholders until
 89→/// subtasks 3-1 and 3-2 wire the real widgets.
 90→fn draw(
 91→    terminal: &mut Terminal<ratatui::backend::CrosstermBackend<Stdout>>,
 92→    app: &mut App,
 93→) -> anyhow::Result<()> {
 94→    terminal.draw(|frame| {
 95→        let area = frame.area();
 96→
 97→        // Three-zone layout: header (2), body (fill), footer (1).
 98→        let zones = Layout::vertical([
 99→            Constraint::Length(2),
100→            Constraint::Min(0),
101→            Constraint::Length(1),
102→        ])
103→        .split(area);
104→
105→        // ── Header (2 rows) ────────────────────────────────────────────
106→        render_header(frame, zones[0], app);
107→
108→        // ── Body (remaining space) ─────────────────────────────────────
109→        render_kanban(frame, zones[1], app);
110→
111→        // ── Footer (1 row) ─────────────────────────────────────────────
112→        let footer = Paragraph::new(
113→            "[h/l]col [j/k]card [↵]actions [/]filter [n]new [q]quit",
114→        )
115→        .style(Style::default().fg(Color::DarkGray));
116→        frame.render_widget(footer, zones[2]);
117→    })?;
118→
119→    Ok(())
120→}
