    22→
    23→// ── TerminalGuard ──────────────────────────────────────────────────────────
    24→
    25→/// RAII guard that enters the alternate screen and enables raw mode on
    26→/// creation, and restores the terminal on `Drop`.
    27→///
    28→/// This ensures clean terminal restoration even on panic — the guard's
    29→/// destructor runs during stack unwinding. A panic hook is installed as
    30→/// an additional safety net for `panic = abort` profiles.
    31→pub struct TerminalGuard {
    32→    _private: (), // prevent construction outside `new()`
    33→}
    34→
    35→impl TerminalGuard {
    36→    /// Enter alternate screen, enable raw mode, and hide the cursor.
    37→    ///
    38→    /// Also installs a panic hook that performs terminal cleanup before
    39→    /// the default handler runs, so the user's terminal is never left
    40→    /// in a broken state.
    41→    pub fn new() -> anyhow::Result<Self> {
    42→        // Install panic hook for terminal cleanup (safety net).
    43→        let original_hook = std::panic::take_hook();
    44→        std::panic::set_hook(Box::new(move |info| {
    45→            // Best-effort cleanup before the default handler.
    46→            let _ = execute!(stdout(), cursor::Show, LeaveAlternateScreen);
    47→            let _ = disable_raw_mode();
    48→            original_hook(info);
    49→        }));
    50→
    51→        enable_raw_mode()?;
    52→        execute!(stdout(), EnterAlternateScreen, cursor::Hide)?;
    53→        Ok(Self { _private: () })
    54→    }
    55→}
    56→
    57→impl Drop for TerminalGuard {
    58→    fn drop(&mut self) {
    59→        // Best-effort cleanup — ignore errors during Drop.
    60→        let _ = execute!(stdout(), cursor::Show, LeaveAlternateScreen);
    61→        let _ = disable_raw_mode();
    62→    }
    63→}
    64→
    65→// ── EventLoop ──────────────────────────────────────────────────────────────
    66→
    67→/// Encapsulates the three background event producers.
    68→///
    69→/// Call [`EventLoop::new`] to spawn the background tasks, then use
    70→/// [`EventLoop::next`] to receive events in the main render loop.
    71→///
    72→/// # Background tasks
    73→///
    74→/// 1. **Crossterm reader** — polls terminal events on a dedicated thread,
    75→///    converts `Key` and `Resize` events to [`AppEvent`] variants.
    76→/// 2. **Tick timer** — sends [`AppEvent::Tick`] every 250ms via
    77→///    `tokio::time::interval`.
    78→/// 3. **Filesystem watcher** — watches `.cards/` state directories for
    79→///    changes, re-reads all cards and sends [`AppEvent::Cards`] with
    80→///    fresh column data.
    81→pub struct EventLoop {
    82→    rx: mpsc::UnboundedReceiver<AppEvent>,
    83→}
    84→
    85→impl EventLoop {
    86→    /// Spawn the three background tasks and return the event loop handle.
    87→    pub fn new(cards_root: &Path) -> Self {
    88→        let (tx, rx) = mpsc::unbounded_channel();
    89→
    90→        // ── 1. Crossterm key/resize reader (blocking → dedicated thread) ──
    91→        let key_tx = tx.clone();
    92→        std::thread::spawn(move || {
    93→            loop {
    94→                // Poll with 50ms timeout so the thread exits promptly
    95→                // when the receiver half is dropped (channel closed).
    96→                match event::poll(Duration::from_millis(50)) {
    97→                    Ok(true) => match event::read() {
    98→                        Ok(Event::Key(key)) => {
    99→                            if key_tx.send(AppEvent::Key(key)).is_err() {
   100→                                return; // receiver dropped — exit
   101→                            }
   102→                        }
   103→                        Ok(Event::Resize(w, h)) => {
   104→                            if key_tx.send(AppEvent::Resize(w, h)).is_err() {
   105→                                return;
   106→                            }
   107→                        }
   108→                        Ok(_) => {} // mouse, focus, paste — ignored
   109→                        Err(_) => return,
   110→                    },
   111→                    Ok(false) => {} // timeout — loop and check again
   112→                    Err(_) => return, // terminal gone
   113→                }
   114→            }
   115→        });
   116→
   117→        // ── 2. Tick timer (250ms) ─────────────────────────────────────────
   118→        let tick_tx = tx.clone();
   119→        tokio::spawn(async move {
   120→            let mut interval = tokio::time::interval(Duration::from_millis(250));
   121→            loop {
   122→                interval.tick().await;
   123→                if tick_tx.send(AppEvent::Tick).is_err() {
   124→                    return; // receiver dropped
   125→                }
   126→            }
   127→        });
   128→
   129→        // ── 3. Filesystem watcher on .cards/ state dirs ───────────────────
   130→        let watch_tx = tx;
   131→        let root = cards_root.to_path_buf();
   132→        spawn_fs_watcher(root, watch_tx);
   133→
   134→        Self { rx }
   135→    }
   136→
   137→    /// Receive the next event from any background producer.
   138→    ///
   139→    /// Returns `None` when all senders have been dropped (shutdown).
   140→    pub async fn next(&mut self) -> Option<AppEvent> {
   141→        self.rx.recv().await
   142→    }
   143→}
