    99→// ── Event ticker ────────────────────────────────────────────────────────────
   100→
   101→/// Maximum number of recent completions stored for the event ticker.
   102→pub const TICKER_CAPACITY: usize = 20;
   103→
   104→/// Separator between ticker entries.
   105→const TICKER_SEP: &str = "  ·  ";
   106→
   107→/// Build the scrolling event ticker string from recent completions.
   108→///
   109→/// Joins all entries with a separator, then uses `tick_offset` to scroll
   110→/// the text left across the available width (demoscene-style marquee).
   111→fn build_ticker_text(completions: &[String], tick_offset: usize, width: usize) -> String {
   112→    if completions.is_empty() || width == 0 {
   113→        return String::new();
   114→    }
   115→
   116→    let joined = completions.join(TICKER_SEP);
   117→    if joined.is_empty() {
   118→        return String::new();
   119→    }
   120→
   121→    // Create a repeating buffer so the scroll wraps smoothly.
   122→    let padded = format!("{}{}{}", joined, TICKER_SEP, joined);
   123→    let total_len = padded.chars().count();
   124→    let offset = tick_offset % total_len;
   125→
   126→    padded
   127→        .chars()
   128→        .cycle()
   129→        .skip(offset)
   130→        .take(width)
   131→        .collect()
   132→}
   133→
   134→// ── Main render ─────────────────────────────────────────────────────────────
   135→
   136→/// Render the header bar into the given area.
   137→///
   138→/// Uses the first row for the main status line and the second row for
   139→/// the scrolling event ticker (only if terminal width ≥ 120).
   140→pub fn render_header(frame: &mut Frame, area: Rect, app: &App) {
   141→    if area.height == 0 || area.width == 0 {
   142→        return;
   143→    }
   144→
   145→    let width = area.width as usize;
   146→
   147→    // ── Line 1: bop · HH:MM:SS · meters · sparkline N/hr ──────────
   148→    let time_str = Local::now().format("%H:%M:%S").to_string();
   149→
   150→    let mut spans: Vec<Span<'static>> = vec![
   151→        Span::styled("bop", Style::default().fg(Color::Cyan)),
   152→        Span::styled(" · ", Style::default().fg(Color::DarkGray)),
   153→        Span::styled(time_str, Style::default().fg(Color::White)),
   154→    ];
   155→
   156→    // Provider meters.
   157→    if !app.provider_meters.is_empty() {
   158→        spans.push(Span::styled(" · ", Style::default().fg(Color::DarkGray)));
   159→        spans.extend(build_meter_spans(&app.provider_meters));
   160→    }
   161→
   162→    // Sparkline + throughput.
   163→    let samples: Vec<u8> = app.throughput.iter().copied().collect();
   164→    let sparkline = build_sparkline(&samples);
   165→    let latest = samples.last().copied().unwrap_or(0);
   166→
   167→    spans.push(Span::styled(" · ", Style::default().fg(Color::DarkGray)));
   168→    spans.push(Span::styled(sparkline, Style::default().fg(Color::Cyan)));
   169→    spans.push(Span::styled(
   170→        format!(" {}/hr", latest),
   171→        Style::default().fg(Color::DarkGray),
   172→    ));
   173→
   174→    let line1 = Line::from(spans);
   175→
   176→    // ── Line 2: event ticker (width >= 120 only) ───────────────────
   177→    let lines = if area.height >= 2 && width >= 120 {
   178→        let completions: Vec<String> = app.recent_completions.iter().cloned().collect();
   179→        let ticker_text = build_ticker_text(&completions, app.tick_count as usize, width);
   180→        let line2 = Line::from(Span::styled(
   181→            ticker_text,
   182→            Style::default().fg(Color::DarkGray),
   183→        ));
   184→        vec![line1, line2]
   185→    } else if area.height >= 2 {
   186→        // Second line is blank when width < 120.
   187→        vec![line1, Line::from("")]
   188→    } else {
   189→        vec![line1]
   190→    };
   191→
   192→    let header = Paragraph::new(lines);
   193→    frame.render_widget(header, area);
   194→}
