 17→/// Launch the interactive TUI kanban board.
 18→///
 19→/// Sets up the terminal guard (alternate screen + raw mode), initialises
 20→/// the application state, spawns background event producers, and enters
 21→/// the main event loop. On exit (q or Ctrl-C), the `TerminalGuard`
 22→/// restores the terminal via its `Drop` impl.
 23→pub async fn run_ui(root: &Path) -> anyhow::Result<()> {
 24→    // Initialise application state from the filesystem.
 25→    let mut app = App::new(root)?;
 26→
 27→    // Enter alternate screen + raw mode (restored on Drop).
 28→    let _guard = TerminalGuard::new()?;
 29→
 30→    // Create ratatui terminal with crossterm backend.
 31→    let backend = ratatui::backend::CrosstermBackend::new(io::stdout());
 32→    let mut terminal = Terminal::new(backend)?;
 33→
 34→    // Spawn background tasks: crossterm reader, tick timer, fs watcher.
 35→    let mut events = EventLoop::new(root);
 36→
 37→    // ── Initial render ─────────────────────────────────────────────────
 38→    draw(&mut terminal, &mut app)?;
 39→
 40→    // ── Main event loop ────────────────────────────────────────────────
 41→    loop {
 42→        let Some(event) = events.next().await else {
 43→            break; // all senders dropped — clean shutdown
 44→        };
 45→
 46→        match event {
 47→            AppEvent::Key(key) => {
 48→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
 49→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
 50→                    && key.code == KeyCode::Char('c');
 51→                let quit = app.mode == Mode::Normal && key.code == KeyCode::Char('q');
 52→
 53→                if ctrl_c || quit {
 54→                    break;
 55→                }
 56→
 57→                // Dispatch remaining keys to mode-specific handler.
 58→                input::handle_key(&mut app, key);
 59→            }
 60→            AppEvent::Resize(_w, _h) => {
 61→                // Resize handling will be implemented in subtask 6-4.
 62→            }
 63→            AppEvent::Tick => {
 64→                app.on_tick();
 65→            }
 66→            AppEvent::Cards(columns) => {
 67→                app.refresh_columns(columns);
 68→            }
 69→            AppEvent::LogLine(line) => {
 70→                app.push_log_line(line);
 71→            }
 72→        }
 73→
 74→        // Re-render after every event.
 75→        draw(&mut terminal, &mut app)?;
 76→    }
 77→
 78→    // _guard drops here → restores alternate screen + raw mode.
 79→    Ok(())
 80→}
 81→
 82→/// Render the three-zone layout: header (2 rows), body (remaining), footer (1–2 rows).
 83→///
 84→/// Uses ratatui's `Layout::vertical` to divide the terminal into the
 85→/// k9s-style three-zone layout. The body zone renders the kanban board
 86→/// via [`render_kanban`]; the footer shows context-sensitive keybinding
 87→/// hints via [`render_footer`]. When terminal height > 30, the footer
 88→/// gets 2 rows to display the secondary F-key bar (mc-style).
 89→fn draw(
 90→    terminal: &mut Terminal<ratatui::backend::CrosstermBackend<Stdout>>,
 91→    app: &mut App,
 92→) -> anyhow::Result<()> {
 93→    terminal.draw(|frame| {
 94→        let area = frame.area();
 95→        let terminal_height = area.height;
 96→
 97→        // Footer gets 2 rows when terminal is tall enough for the F-key bar.
 98→        let footer_height = if terminal_height > 30 { 2 } else { 1 };
 99→
100→        // Three-zone layout: header (2), body (fill), footer (1–2).
101→        let zones = Layout::vertical([
102→            Constraint::Length(2),
103→            Constraint::Min(0),
104→            Constraint::Length(footer_height),
105→        ])
106→        .split(area);
107→
108→        // ── Header (2 rows) ────────────────────────────────────────────
109→        render_header(frame, zones[0], app);
110→
111→        // ── Body (remaining space) ─────────────────────────────────────
112→        render_kanban(frame, zones[1], app);
113→
114→        // ── Footer (1–2 rows) ──────────────────────────────────────────
115→        render_footer(frame, zones[2], app, terminal_height);
116→    })?;
117→
118→    Ok(())
119→}
