    25→        Mode::Filter => {
    26→            // Will be wired in subtask 5-1.
    27→        }
    28→        Mode::ActionPopup => {
    29→            // Will be wired in subtask 4-2.
    30→        }
    31→        Mode::Detail => {
    32→            // Will be wired in subtask 4-1.
    33→        }
    34→        Mode::LogTail => {
    35→            // Will be wired in subtask 4-3.
    36→        }
    37→        Mode::NewCard => {
    38→            // Will be wired in subtask 5-2.
    39→        }
