    46→// ── Normal mode ─────────────────────────────────────────────────────────────
    47→
    48→/// Handle key events in Normal mode.
    49→///
    50→/// Navigation:
    51→/// - `h` — move focus to previous column (wrapping, skipping collapsed)
    52→/// - `l` — move focus to next column (wrapping, skipping collapsed)
    53→/// - `j` — select next card in current column
    54→/// - `k` — select previous card in current column
    55→fn handle_normal(app: &mut App, key: KeyEvent) {
    56→    match key.code {
    57→        KeyCode::Char('h') | KeyCode::Left => {
    58→            move_col_focus(app, Direction::Left);
    59→        }
    60→        KeyCode::Char('l') | KeyCode::Right => {
    61→            move_col_focus(app, Direction::Right);
    62→        }
    63→        KeyCode::Char('j') | KeyCode::Down => {
    64→            move_card_selection(app, Direction::Down);
    65→        }
    66→        KeyCode::Char('k') | KeyCode::Up => {
    67→            move_card_selection(app, Direction::Up);
    68→        }
    69→        _ => {
    70→            // Other Normal-mode keys (d, /, n, Enter, !, Tab, Shift+H/L)
    71→            // will be wired in subsequent subtasks.
    72→        }
    73→    }
    74→}
    75→
    76→// ── Navigation helpers ──────────────────────────────────────────────────────
    77→
    78→/// Direction for navigation movement.
    79→enum Direction {
    80→    Left,
    81→    Right,
    82→    Up,
    83→    Down,
    84→}
    85→
    86→/// Move column focus left or right, wrapping at boundaries.
    87→///
    88→/// Skips collapsed (empty) columns — if all columns are collapsed,
    89→/// focus stays at index 0.
    90→fn move_col_focus(app: &mut App, dir: Direction) {
    91→    let len = app.columns.len();
    92→    if len == 0 {
    93→        return;
    94→    }
    95→
    96→    let step: isize = match dir {
    97→        Direction::Left => -1,
    98→        Direction::Right => 1,
    99→        _ => return,
   100→    };
   101→
   102→    // Try up to `len` positions to find a non-collapsed column.
   103→    let mut candidate = app.col_focus as isize;
   104→    for _ in 0..len {
   105→        candidate = (candidate + step).rem_euclid(len as isize);
   106→        let idx = candidate as usize;
   107→        if !app.columns[idx].collapsed {
   108→            app.col_focus = idx;
   109→            return;
   110→        }
   111→    }
   112→
   113→    // All columns collapsed — stay where we are.
   114→}
   115→
   116→/// Move card selection up or down within the currently focused column.
   117→///
   118→/// Wraps around at both ends: pressing `j` on the last card selects the
   119→/// first, and pressing `k` on the first card selects the last.
   120→fn move_card_selection(app: &mut App, dir: Direction) {
   121→    let Some(col) = app.focused_column_mut() else {
   122→        return;
   123→    };
   124→
   125→    let card_count = col.cards.len();
   126→    if card_count == 0 {
   127→        return;
   128→    }
   129→
   130→    let current = col.list_state.selected().unwrap_or(0);
   131→
   132→    let new_idx = match dir {
   133→        Direction::Up => {
   134→            if current == 0 {
   135→                card_count - 1
   136→            } else {
   137→                current - 1
   138→            }
   139→        }
   140→        Direction::Down => {
   141→            if current >= card_count - 1 {
   142→                0
   143→            } else {
   144→                current + 1
   145→            }
   146→        }
   147→        _ => return,
   148→    };
   149→
   150→    col.list_state.select(Some(new_idx));
   151→}
