 82→/// Render the three-zone layout: header (2 rows), body (remaining), footer (1–2 rows).
 83→///
 84→/// Uses ratatui's `Layout::vertical` to divide the terminal into the
 85→/// k9s-style three-zone layout. The body zone renders the kanban board
 86→/// via [`render_kanban`]; the footer shows context-sensitive keybinding
 87→/// hints via [`render_footer`]. When terminal height > 30, the footer
 88→/// gets 2 rows to display the secondary F-key bar (mc-style).
 89→fn draw(
 90→    terminal: &mut Terminal<ratatui::backend::CrosstermBackend<Stdout>>,
 91→    app: &mut App,
 92→) -> anyhow::Result<()> {
 93→    terminal.draw(|frame| {
 94→        let area = frame.area();
 95→        let terminal_height = area.height;
 96→
 97→        // Footer gets 2 rows when terminal is tall enough for the F-key bar.
 98→        let footer_height = if terminal_height > 30 { 2 } else { 1 };
 99→
100→        // Three-zone layout: header (2), body (fill), footer (1–2).
101→        let zones = Layout::vertical([
102→            Constraint::Length(2),
103→            Constraint::Min(0),
104→            Constraint::Length(footer_height),
105→        ])
106→        .split(area);
107→
108→        // ── Header (2 rows) ────────────────────────────────────────────
109→        render_header(frame, zones[0], app);
110→
111→        // ── Body (remaining space) ─────────────────────────────────────
112→        render_kanban(frame, zones[1], app);
113→
114→        // ── Footer (1–2 rows) ──────────────────────────────────────────
115→        render_footer(frame, zones[2], app, terminal_height);
116→    })?;
117→
118→    Ok(())
119→}
