    23→
    24→/// State glyph for column headers and collapsed dividers.
    25→///
    26→/// Matches the spec's visual language: `·` pending, `⚙` running,
    27→/// `✓` done, `✗` failed, `~` merged.
    28→fn state_glyph(state: &str) -> &'static str {
    29→    match state {
    30→        "pending" => "·",
    31→        "running" => "⚙",
    32→        "done" => "✓",
    33→        "failed" => "✗",
    34→        "merged" => "~",
    35→        _ => "?",
    36→    }
    37→}
    38→
    39→/// Card marker glyph for list rows (matches render/full.rs pattern).
    40→fn card_marker(state: &str) -> &'static str {
    41→    match state {
    42→        "running" => "▶",
    43→        "done" | "merged" => "✓",
    44→        "failed" => "✗",
    45→        _ => "·",
    46→    }
    47→}
    48→
    49→/// RGB color for a given state (matches colors.rs hex values).
    50→///
    51→/// Uses 24-bit RGB for consistent appearance across terminals that
    52→/// support truecolor (which ratatui auto-detects).
    53→fn state_ratatui_color(state: &str) -> Color {
    54→    match state {
    55→        "pending" => Color::Rgb(0x3A, 0x5A, 0x8A),
    56→        "running" => Color::Rgb(0xB8, 0x69, 0x0F),
    57→        "done" => Color::Rgb(0x1E, 0x8A, 0x45),
    58→        "failed" => Color::Rgb(0xC4, 0x30, 0x30),
    59→        "merged" => Color::Rgb(0x6B, 0x3D, 0xB8),
    60→        _ => Color::Gray,
    61→    }
    62→}
    63→
    64→/// Moon-quarter glyph for phase progress (matches render/full.rs).
    65→///
    66→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    67→fn moon_glyph(frac: f32) -> char {
    68→    if frac < 0.25 {
    69→        '◔'
    70→    } else if frac < 0.50 {
    71→        '◑'
    72→    } else if frac < 0.75 {
    73→        '◕'
    74→    } else {
    75→        '●'
    76→    }
    77→}
