   196→pub fn list_cards(root: &Path, state_filter: &str) -> anyhow::Result<()> {
   197→    let caps = TermCaps::detect();
   198→    let groups = collect_card_groups(root, state_filter)?;
   199→    let card_stats = calculate_stats(root)?;
   200→    let stats = stats_to_render_stats(&card_stats);
   201→    let output = render::render_board(&caps, &groups, &stats);
   202→    print!("{}", output);
   203→    Ok(())
   204→}
