     1→/// Kanban board widget — horizontal columns of card lists.
     2→///
     3→/// Renders columns left-to-right: pending, running, done, failed, merged.
     4→/// Empty columns collapse to a 3-char narrow divider showing only the state
     5→/// glyph (`·`, `⚙`, `✓`, `✗`, `~`). Non-collapsed columns share remaining
     6→/// width equally via `Constraint::Fill(1)` and display a bordered `List` of
     7→/// card rows.
     8→///
     9→/// Focus and WIP indicators:
    10→/// - Focused column: `Color::Yellow` border
    11→/// - Running column ≥75% WIP: amber title
    12→/// - Running column at 100% WIP: red title + border
    13→use ratatui::layout::{Constraint, Layout, Rect};
    14→use ratatui::style::{Color, Modifier, Style};
    15→use ratatui::text::{Line, Span};
    16→use ratatui::widgets::{Block, List, ListItem, Paragraph};
    17→use ratatui::Frame;
    18→
    19→use crate::render::CardView;
    20→use crate::ui::app::{App, KanbanColumn};
    21→
    22→// ── Glyph helpers ────────────────────────────────────────────────────────────
    23→
    24→/// State glyph for column headers and collapsed dividers.
    25→///
    26→/// Matches the spec's visual language: `·` pending, `⚙` running,
    27→/// `✓` done, `✗` failed, `~` merged.
    28→fn state_glyph(state: &str) -> &'static str {
    29→    match state {
    30→        "pending" => "·",
    31→        "running" => "⚙",
    32→        "done" => "✓",
    33→        "failed" => "✗",
    34→        "merged" => "~",
    35→        _ => "?",
    36→    }
    37→}
    38→
    39→/// Card marker glyph for list rows (matches render/full.rs pattern).
    40→fn card_marker(state: &str) -> &'static str {
    41→    match state {
    42→        "running" => "▶",
    43→        "done" | "merged" => "✓",
    44→        "failed" => "✗",
    45→        _ => "·",
    46→    }
    47→}
    48→
    49→/// RGB color for a given state (matches colors.rs hex values).
    50→///
    51→/// Uses 24-bit RGB for consistent appearance across terminals that
    52→/// support truecolor (which ratatui auto-detects).
    53→fn state_ratatui_color(state: &str) -> Color {
    54→    match state {
