    27→        }
    28→        Mode::ActionPopup => {
    29→            // Will be wired in subtask 4-2.
    30→        }
    31→        Mode::Detail => handle_detail(app, key),
    32→        Mode::LogTail => {
    33→            // Will be wired in subtask 4-3.
    34→        }
    35→        Mode::NewCard => {
    36→            // Will be wired in subtask 5-2.
    37→        }
    38→        Mode::Subshell => {
    39→            // Subshell mode suspends the TUI — no key handling here.
    40→        }
    41→    }
