    44→// ── Normal mode ─────────────────────────────────────────────────────────────
    45→
    46→/// Handle key events in Normal mode.
    47→///
    48→/// Navigation:
    49→/// - `h` — move focus to previous column (wrapping, skipping collapsed)
    50→/// - `l` — move focus to next column (wrapping, skipping collapsed)
    51→/// - `j` — select next card in current column
    52→/// - `k` — select previous card in current column
    53→fn handle_normal(app: &mut App, key: KeyEvent) {
    54→    match key.code {
    55→        KeyCode::Char('h') | KeyCode::Left => {
    56→            move_col_focus(app, Direction::Left);
    57→        }
    58→        KeyCode::Char('l') | KeyCode::Right => {
    59→            move_col_focus(app, Direction::Right);
    60→        }
    61→        KeyCode::Char('j') | KeyCode::Down => {
    62→            move_card_selection(app, Direction::Down);
    63→        }
    64→        KeyCode::Char('k') | KeyCode::Up => {
    65→            move_card_selection(app, Direction::Up);
    66→        }
    67→        KeyCode::Char('d') => {
    68→            // Only enter Detail mode if a card is selected.
    69→            if app.selected_card().is_some() {
    70→                app.detail_scroll = 0;
    71→                app.mode = Mode::Detail;
    72→            }
    73→        }
    74→        _ => {
    75→            // Other Normal-mode keys (/, n, Enter, !, Tab, Shift+H/L)
    76→            // will be wired in subsequent subtasks.
    77→        }
    78→    }
    79→}
