    81→// ── Detail mode ─────────────────────────────────────────────────────────────
    82→
    83→/// Handle key events in Detail mode.
    84→///
    85→/// Navigation:
    86→/// - `j` / `Down` — scroll detail content down one line
    87→/// - `k` / `Up` — scroll detail content up one line
    88→/// - `Esc` — return to Normal mode
    89→fn handle_detail(app: &mut App, key: KeyEvent) {
    90→    match key.code {
    91→        KeyCode::Char('j') | KeyCode::Down => {
    92→            app.detail_scroll = app.detail_scroll.saturating_add(1);
    93→        }
    94→        KeyCode::Char('k') | KeyCode::Up => {
    95→            app.detail_scroll = app.detail_scroll.saturating_sub(1);
    96→        }
    97→        KeyCode::Esc => {
    98→            app.mode = Mode::Normal;
    99→        }
   100→        _ => {
   101→            // Other Detail-mode keys (F3, p, r) will trigger actions
   102→            // in subsequent subtasks.
   103→        }
   104→    }
   105→}
