   107→// ── Navigation helpers ──────────────────────────────────────────────────────
   108→
   109→/// Direction for navigation movement.
   110→enum Direction {
   111→    Left,
   112→    Right,
   113→    Up,
   114→    Down,
   115→}
   116→
   117→/// Move column focus left or right, wrapping at boundaries.
   118→///
   119→/// Skips collapsed (empty) columns — if all columns are collapsed,
   120→/// focus stays at index 0.
   121→fn move_col_focus(app: &mut App, dir: Direction) {
   122→    let len = app.columns.len();
   123→    if len == 0 {
   124→        return;
   125→    }
   126→
   127→    let step: isize = match dir {
   128→        Direction::Left => -1,
   129→        Direction::Right => 1,
   130→        _ => return,
   131→    };
   132→
   133→    // Try up to `len` positions to find a non-collapsed column.
   134→    let mut candidate = app.col_focus as isize;
   135→    for _ in 0..len {
   136→        candidate = (candidate + step).rem_euclid(len as isize);
   137→        let idx = candidate as usize;
   138→        if !app.columns[idx].collapsed {
   139→            app.col_focus = idx;
   140→            return;
   141→        }
   142→    }
   143→
   144→    // All columns collapsed — stay where we are.
   145→}
   146→
   147→/// Move card selection up or down within the currently focused column.
   148→///
   149→/// Wraps around at both ends: pressing `j` on the last card selects the
   150→/// first, and pressing `k` on the first card selects the last.
   151→fn move_card_selection(app: &mut App, dir: Direction) {
   152→    let Some(col) = app.focused_column_mut() else {
   153→        return;
   154→    };
   155→
   156→    let card_count = col.cards.len();
   157→    if card_count == 0 {
   158→        return;
   159→    }
   160→
   161→    let current = col.list_state.selected().unwrap_or(0);
   162→
   163→    let new_idx = match dir {
   164→        Direction::Up => {
   165→            if current == 0 {
   166→                card_count - 1
   167→            } else {
   168→                current - 1
   169→            }
   170→        }
   171→        Direction::Down => {
   172→            if current >= card_count - 1 {
   173→                0
   174→            } else {
   175→                current + 1
   176→            }
   177→        }
   178→        _ => return,
   179→    };
   180→
   181→    col.list_state.select(Some(new_idx));
   182→}
