 16→    if !follow {
 17→        // Print all existing content once
 18→        print_log_section("stdout", &stdout_log, is_tty)?;
 19→        print_log_section("stderr", &stderr_log, is_tty)?;
 20→        return Ok(());
 21→    }
 22→
 23→    // --follow: open both files and stream new bytes as they arrive
 24→    let mut stdout_file = fs::File::open(&stdout_log)
 25→        .unwrap_or_else(|_| fs::File::open("/dev/null").expect("open /dev/null"));
 26→    let mut stderr_file = fs::File::open(&stderr_log)
 27→        .unwrap_or_else(|_| fs::File::open("/dev/null").expect("open /dev/null"));
 28→
 29→    // Drain any existing content first
 30→    let mut buf = Vec::new();
 31→    stdout_file.read_to_end(&mut buf)?;
 32→    if !buf.is_empty() {
 33→        print!("{}", colorize_chunk(&buf, is_tty));
 34→    }
 35→    let mut stdout_pos = stdout_file.stream_position()?;
 36→    buf.clear();
 37→
 38→    stderr_file.read_to_end(&mut buf)?;
 39→    if !buf.is_empty() {
 40→        eprint!("{}", colorize_chunk(&buf, is_tty));
 41→    }
 42→    let mut stderr_pos = stderr_file.stream_position()?;
 43→
 44→    loop {
 45→        tokio::time::sleep(Duration::from_millis(200)).await;
 46→
 47→        // Re-open if file was rotated/created after we started
 48→        if !stdout_log.exists() {
 49→            if let Ok(f) = fs::File::open(&stdout_log) {
 50→                stdout_file = f;
 51→                stdout_pos = 0;
 52→            }
 53→        }
 54→        if !stderr_log.exists() {
 55→            if let Ok(f) = fs::File::open(&stderr_log) {
 56→                stderr_file = f;
 57→                stderr_pos = 0;
 58→            }
 59→        }
 60→
 61→        // Read any new bytes from stdout
 62→        stdout_file.seek(SeekFrom::Start(stdout_pos))?;
 63→        buf.clear();
 64→        stdout_file.read_to_end(&mut buf)?;
 65→        if !buf.is_empty() {
 66→            print!("{}", colorize_chunk(&buf, is_tty));
 67→            std::io::stdout().flush()?;
 68→            stdout_pos += buf.len() as u64;
 69→        }
 70→
 71→        // Read any new bytes from stderr
 72→        stderr_file.seek(SeekFrom::Start(stderr_pos))?;
 73→        buf.clear();
 74→        stderr_file.read_to_end(&mut buf)?;
 75→        if !buf.is_empty() {
 76→            eprint!("{}", colorize_chunk(&buf, is_tty));
 77→            std::io::stderr().flush()?;
 78→            stderr_pos += buf.len() as u64;
 79→        }
 80→
 81→        // Stop following once the card leaves running/
 82→        let still_running = paths::find_card_in_state(root, id, "running");
 83→        if !still_running {
 84→            break;
 85→        }
 86→    }
 87→
 88→    Ok(())
 89→}
 90→
 91→fn colorize_log_line(line: &str) -> String {
 92→    const R: &str = "\x1b[0m";
 93→    if line.contains("ERROR") || line.contains("error:") || line.contains("FAILED") {
 94→        return format!("\x1b[1;31m{}{}", line, R);
 95→    }
 96→    if line.contains("WARN") || line.contains("warning:") {
 97→        return format!("\x1b[33m{}{}", line, R);
 98→    }
 99→    if line.contains("INFO") {
100→        return format!("\x1b[36m{}{}", line, R);
101→    }
102→    if line.contains("DEBUG") || line.contains("TRACE") {
103→        return format!("\x1b[2m{}{}", line, R);
104→    }
105→    if line.contains("→ merged") || line.contains("-> merged") {
106→        return format!("\x1b[1;35m{}{}", line, R);
107→    }
108→    if line.contains("→ done") || line.contains("-> done") {
109→        return format!("\x1b[1;32m{}{}", line, R);
110→    }
111→    if line.contains("→ failed") || line.contains("-> failed") {
112→        return format!("\x1b[1;31m{}{}", line, R);
113→    }
114→    if line.contains("→ running") || line.contains("-> running") {
115→        return format!("\x1b[1;33m{}{}", line, R);
116→    }
117→    line.to_string()
118→}
119→
120→fn colorize_chunk(bytes: &[u8], is_tty: bool) -> String {
121→    let text = String::from_utf8_lossy(bytes);
122→    if !is_tty {
123→        return text.into_owned();
124→    }
125→    text.lines()
126→        .map(colorize_log_line)
127→        .collect::<Vec<_>>()
128→        .join("\n")
129→        + if text.ends_with('\n') { "\n" } else { "" }
130→}
131→
132→fn print_log_section(label: &str, path: &Path, is_tty: bool) -> anyhow::Result<()> {
133→    if !path.exists() {
134→        println!("=== {} (no file) ===", label);
135→        return Ok(());
136→    }
137→    let content = fs::read_to_string(path)?;
138→    if is_tty {
139→        println!("\x1b[1m=== {} ===\x1b[0m", label);
140→    } else {
141→        println!("=== {} ===", label);
142→    }
143→    if is_tty {
144→        for line in content.lines() {
145→            println!("{}", colorize_log_line(line));
146→        }
147→        if !content.ends_with('\n') && !content.is_empty() {
148→            // already printed trailing newline via println
149→        }
150→    } else {
151→        print!("{}", content);
152→        if !content.ends_with('\n') && !content.is_empty() {
153→            println!();
154→        }
155→    }
156→    Ok(())
157→}
