     1→/// Action popup overlay widget — centered command palette for card actions.
     2→///
     3→/// Renders as a centered popup overlay using ratatui `Clear` + bordered
     4→/// `Block`. Shows a list of actions filtered by the selected card's state:
     5→///
     6→/// - **running**: `[F3]logs  [z]zellij  [p]pause  [k]kill`
     7→/// - **done**: `[r]retry`
     8→/// - **failed**: `[r]retry`
     9→/// - **pending**: `[k]kill(remove)`
    10→///
    11→/// Each action is a selectable `List` item. Press `↵` in Normal mode to
    12→/// enter `Mode::ActionPopup`; `Esc` returns to Normal. Selecting an action
    13→/// with `↵` executes it (actions are dispatched via `ActionKind`).
    14→use ratatui::layout::Rect;
    15→use ratatui::style::{Color, Modifier, Style};
    16→use ratatui::text::{Line, Span};
    17→use ratatui::widgets::{Block, Clear, List, ListItem, ListState};
    18→use ratatui::Frame;
    19→
    20→// ── Action types ────────────────────────────────────────────────────────────
    21→
    22→/// The kind of action a user can perform on a card.
    23→///
    24→/// Each variant maps to an existing `cmd_*` function in `cards.rs` or
    25→/// a mode transition (e.g. `LogTail` opens the log tail overlay).
    26→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    27→pub enum ActionKind {
    28→    /// Open log tail overlay (F3 / `Mode::LogTail`).
    29→    Logs,
    30→    /// Open card worktree in a Zellij pane.
    31→    Zellij,
    32→    /// Pause a running card (`cmd_pause`).
    33→    Pause,
    34→    /// Kill a running card (`cmd_kill`).
    35→    Kill,
    36→    /// Retry a done/failed card (`cmd_retry`).
    37→    Retry,
    38→    /// Remove a pending card from the queue.
    39→    Remove,
    40→}
    41→
    42→/// A single action entry in the popup list.
    43→#[derive(Debug, Clone)]
    44→pub struct ActionEntry {
    45→    /// The action kind (used for dispatch).
    46→    pub kind: ActionKind,
    47→    /// Keybinding hint shown in the list (e.g. "[F3]").
    48→    pub key_hint: &'static str,
    49→    /// Human-readable label (e.g. "logs").
    50→    pub label: &'static str,
    51→}
    52→
    53→// ── State-filtered action lists ─────────────────────────────────────────────
    54→
    55→/// Return the list of actions available for a given card state.
    56→///
    57→/// Actions are filtered based on what makes sense for the card's current
    58→/// lifecycle state:
    59→/// - `running` → logs, zellij, pause, kill
    60→/// - `done` → retry
    61→/// - `failed` → retry
    62→/// - `pending` → kill(remove)
    63→/// - `merged` → (no actions)
    64→pub fn actions_for_state(state: &str) -> Vec<ActionEntry> {
    65→    match state {
    66→        "running" => vec![
    67→            ActionEntry {
    68→                kind: ActionKind::Logs,
    69→                key_hint: "[F3]",
    70→                label: "logs",
    71→            },
    72→            ActionEntry {
    73→                kind: ActionKind::Zellij,
    74→                key_hint: "[z]",
    75→                label: "zellij",
    76→            },
    77→            ActionEntry {
    78→                kind: ActionKind::Pause,
    79→                key_hint: "[p]",
    80→                label: "pause",
    81→            },
    82→            ActionEntry {
    83→                kind: ActionKind::Kill,
    84→                key_hint: "[k]",
    85→                label: "kill",
    86→            },
    87→        ],
    88→        "done" => vec![ActionEntry {
    89→            kind: ActionKind::Retry,
    90→            key_hint: "[r]",
    91→            label: "retry",
    92→        }],
    93→        "failed" => vec![ActionEntry {
    94→            kind: ActionKind::Retry,
    95→            key_hint: "[r]",
    96→            label: "retry",
    97→        }],
    98→        "pending" => vec![ActionEntry {
    99→            kind: ActionKind::Remove,
   100→            key_hint: "[k]",
   101→            label: "kill (remove)",
   102→        }],
   103→        _ => vec![], // merged or unknown — no actions
   104→    }
   105→}
   106→
   107→// ── Rendering ───────────────────────────────────────────────────────────────
   108→
   109→/// Render the action popup overlay centered in the given body area.
   110→///
   111→/// Uses ratatui `Clear` to erase the underlying kanban content, then draws
   112→/// a bordered `Block` with a selectable `List` of state-filtered actions.
   113→///
   114→/// The popup is sized to fit the action list: width is clamped between
   115→/// 30 and 50 characters, height is the action count + 2 (for borders).
   116→pub fn render_action_popup(
   117→    frame: &mut Frame,
   118→    body_area: Rect,
   119→    card_state: &str,
   120→    card_id: &str,
   121→    action_list_state: &mut ListState,
   122→) {
   123→    let actions = actions_for_state(card_state);
   124→
   125→    if actions.is_empty() {
   126→        // No actions available — render a small "no actions" popup.
   127→        render_empty_popup(frame, body_area, card_id);
   128→        return;
   129→    }
   130→
   131→    // Popup dimensions.
   132→    let popup_width = 36u16.min(body_area.width.saturating_sub(4));
   133→    let popup_height = (actions.len() as u16 + 2).min(body_area.height.saturating_sub(2));
   134→
   135→    let popup_area = centered_rect(popup_width, popup_height, body_area);
   136→
   137→    // Clear the underlying content.
   138→    frame.render_widget(Clear, popup_area);
   139→
   140→    // Build the bordered block with title.
   141→    let title = format!(" {} ", card_id);
   142→    let block = Block::bordered()
   143→        .title(title)
   144→        .title_style(
   145→            Style::default()
   146→                .fg(Color::Yellow)
   147→                .add_modifier(Modifier::BOLD),
   148→        )
   149→        .border_style(Style::default().fg(Color::Yellow));
   150→
   151→    // Build list items from actions.
   152→    let items: Vec<ListItem> = actions
   153→        .iter()
   154→        .map(|action| {
   155→            let line = Line::from(vec![
   156→                Span::styled(
   157→                    format!("{} ", action.key_hint),
   158→                    Style::default().fg(Color::Cyan),
   159→                ),
   160→                Span::styled(action.label, Style::default().fg(Color::White)),
   161→            ]);
   162→            ListItem::new(line)
   163→        })
   164→        .collect();
   165→
   166→    let list = List::new(items)
   167→        .block(block)
   168→        .highlight_style(
   169→            Style::default()
   170→                .fg(Color::Yellow)
   171→                .add_modifier(Modifier::BOLD),
   172→        )
   173→        .highlight_symbol("▸ ");
   174→
   175→    frame.render_stateful_widget(list, popup_area, action_list_state);
   176→}
   177→
   178→/// Render a small popup indicating no actions are available.
   179→fn render_empty_popup(frame: &mut Frame, body_area: Rect, card_id: &str) {
   180→    let popup_width = 30u16.min(body_area.width.saturating_sub(4));
   181→    let popup_height = 3u16.min(body_area.height.saturating_sub(2));
   182→
   183→    let popup_area = centered_rect(popup_width, popup_height, body_area);
   184→    frame.render_widget(Clear, popup_area);
   185→
   186→    let title = format!(" {} ", card_id);
   187→    let block = Block::bordered()
   188→        .title(title)
   189→        .title_style(
   190→            Style::default()
   191→                .fg(Color::DarkGray)
   192→                .add_modifier(Modifier::BOLD),
   193→        )
   194→        .border_style(Style::default().fg(Color::DarkGray));
   195→
   196→    let paragraph = ratatui::widgets::Paragraph::new(Line::from(Span::styled(
   197→        "no actions available",
   198→        Style::default().fg(Color::DarkGray),
   199→    )))
   200→    .block(block);
   201→
   202→    frame.render_widget(paragraph, popup_area);
   203→}
   204→
   205→/// Compute a centered `Rect` of the given width and height within `area`.
   206→fn centered_rect(width: u16, height: u16, area: Rect) -> Rect {
   207→    let x = area.x + (area.width.saturating_sub(width)) / 2;
   208→    let y = area.y + (area.height.saturating_sub(height)) / 2;
   209→    Rect::new(x, y, width.min(area.width), height.min(area.height))
   210→}
