    65→///
    66→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    67→fn moon_glyph(frac: f32) -> char {
    68→    if frac < 0.25 {
    69→        '◔'
    70→    } else if frac < 0.50 {
    71→        '◑'
    72→    } else if frac < 0.75 {
    73→        '◕'
    74→    } else {
    75→        '●'
    76→    }
    77→}
