    79→/// Format seconds into human-readable "XmYYs" or "Xs" (matches render/full.rs).
    80→fn format_duration(secs: u64) -> String {
    81→    if secs >= 60 {
    82→        format!("{}m{:02}s", secs / 60, secs % 60)
    83→    } else {
    84→        format!("{}s", secs)
    85→    }
    86→}
