    90→/// Build the column title `Line` with state glyph, name, and count.
    91→///
    92→/// Running columns with a WIP limit show `⚙ RUNNING (N/M)`, with color
    93→/// changing at 75% (amber) and 100% (red) saturation.
    94→fn column_title(col: &KanbanColumn) -> Line<'static> {
    95→    let glyph = state_glyph(&col.state);
    96→    let name = col.state.to_uppercase();
    97→    let count = col.cards.len();
    98→
    99→    let title_text = if col.state == "running" {
   100→        if let Some(limit) = col.wip_limit {
   101→            format!(" {} {} ({}/{}) ", glyph, name, count, limit)
   102→        } else {
   103→            format!(" {} {} ({}) ", glyph, name, count)
   104→        }
   105→    } else {
   106→        format!(" {} {} ({}) ", glyph, name, count)
   107→    };
