     1→/// Key input handling dispatched by current [`Mode`].
     2→///
     3→/// Each mode has its own handler function that processes [`KeyEvent`]s and
     4→/// mutates [`App`] state accordingly. The main entry point [`handle_key`]
     5→/// dispatches to the correct handler based on `app.mode`.
     6→///
     7→/// Normal mode keybindings:
     8→/// - `h` / `l` — move column focus left / right (wrapping)
     9→/// - `j` / `k` — move selected card down / up within current column
    10→///
    11→/// Other modes (Filter, ActionPopup, Detail, LogTail, NewCard) will be
    12→/// wired in subsequent subtasks.
    13→use crossterm::event::{KeyCode, KeyEvent};
    14→
    15→use super::app::{App, Mode};
    16→use crate::ui::widgets::action::{actions_for_state, ActionKind};
    17→use crate::ui::widgets::newcard::create_card;
    18→
    19→/// Dispatch a key event to the handler for the current mode.
    20→///
    21→/// Returns without effect for modes that don't yet have handlers wired
    22→/// (they will be added in later subtasks). The quit keys (q, Ctrl-C) are
    23→/// handled in the event loop before this function is called.
    24→pub fn handle_key(app: &mut App, key: KeyEvent) {
    25→    match app.mode {
    26→        Mode::Normal => handle_normal(app, key),
    27→        Mode::Filter => handle_filter(app, key),
    28→        Mode::ActionPopup => handle_action_popup(app, key),
    29→        Mode::Detail => handle_detail(app, key),
    30→        Mode::LogTail => handle_logtail(app, key),
    31→        Mode::NewCard => handle_newcard(app, key),
    32→        Mode::Subshell => {
    33→            // Subshell mode suspends the TUI — no key handling here.
    34→        }
    35→    }
    36→}
    37→
    38→// ── Normal mode ─────────────────────────────────────────────────────────────
    39→
    40→/// Handle key events in Normal mode.
    41→///
    42→/// Navigation:
    43→/// - `h` — move focus to previous column (wrapping, skipping collapsed)
    44→/// - `l` — move focus to next column (wrapping, skipping collapsed)
    45→/// - `j` — select next card in current column
    46→/// - `k` — select previous card in current column
    47→fn handle_normal(app: &mut App, key: KeyEvent) {
    48→    match key.code {
    49→        KeyCode::Char('h') | KeyCode::Left => {
    50→            move_col_focus(app, Direction::Left);
    51→        }
    52→        KeyCode::Char('l') | KeyCode::Right => {
    53→            move_col_focus(app, Direction::Right);
    54→        }
    55→        KeyCode::Char('j') | KeyCode::Down => {
    56→            move_card_selection(app, Direction::Down);
    57→        }
    58→        KeyCode::Char('k') | KeyCode::Up => {
    59→            move_card_selection(app, Direction::Up);
    60→        }
    61→        KeyCode::Char('d') => {
    62→            // Only enter Detail mode if a card is selected.
    63→            if app.selected_card().is_some() {
    64→                app.detail_scroll = 0;
    65→                app.mode = Mode::Detail;
    66→            }
    67→        }
    68→        KeyCode::Char('/') => {
    69→            app.enter_filter_mode();
    70→        }
    71→        KeyCode::Enter => {
    72→            // Open action popup for the selected card.
    73→            app.open_action_popup();
    74→        }
    75→        KeyCode::Char('n') => {
    76→            app.newcard_input.clear();
    77→            app.mode = Mode::NewCard;
    78→        }
    79→        _ => {
    80→            // Other Normal-mode keys (!, Tab, Shift+H/L)
    81→            // will be wired in subsequent subtasks.
    82→        }
    83→    }
    84→}
    85→
    86→// ── Filter mode ─────────────────────────────────────────────────────────────
    87→
    88→/// Handle key events in Filter mode.
    89→///
    90→/// Keystrokes are appended to the filter query string. Special keys:
    91→/// - `Esc` — clear the filter and return to Normal mode
    92→/// - `Enter` — confirm the filter (stay in Normal with filter active)
    93→/// - `Backspace` — delete last character from query
    94→/// - Any printable `Char` — append to query
    95→///
    96→/// On each keystroke that modifies the query, the filter collapse state
    97→/// is recalculated so columns with no matches collapse in real-time.
    98→fn handle_filter(app: &mut App, key: KeyEvent) {
    99→    match key.code {
   100→        KeyCode::Esc => {
   101→            app.clear_filter();
   102→        }
   103→        KeyCode::Enter => {
   104→            app.confirm_filter();
   105→        }
   106→        KeyCode::Backspace => {
   107→            if let Some(ref mut state) = app.filter_state {
   108→                state.query.pop();
   109→                app.filter = if state.query.is_empty() {
   110→                    None
   111→                } else {
   112→                    Some(state.query.clone())
   113→                };
   114→            }
   115→            app.apply_filter_collapse();
   116→        }
   117→        KeyCode::Char(c) => {
   118→            if let Some(ref mut state) = app.filter_state {
   119→                state.query.push(c);
   120→                app.filter = Some(state.query.clone());
   121→            }
   122→            app.apply_filter_collapse();
   123→        }
   124→        _ => {}
   125→    }
   126→}
   127→
   128→// ── Detail mode ─────────────────────────────────────────────────────────────
   129→
   130→/// Handle key events in Detail mode.
   131→///
   132→/// Navigation:
   133→/// - `j` / `Down` — scroll detail content down one line
   134→/// - `k` / `Up` — scroll detail content up one line
   135→/// - `Esc` — return to Normal mode
   136→fn handle_detail(app: &mut App, key: KeyEvent) {
   137→    match key.code {
   138→        KeyCode::Char('j') | KeyCode::Down => {
   139→            app.detail_scroll = app.detail_scroll.saturating_add(1);
   140→        }
   141→        KeyCode::Char('k') | KeyCode::Up => {
   142→            app.detail_scroll = app.detail_scroll.saturating_sub(1);
   143→        }
   144→        KeyCode::Esc => {
   145→            app.mode = Mode::Normal;
   146→        }
   147→        _ => {
   148→            // Other Detail-mode keys (F3, p, r) will trigger actions
   149→            // in subsequent subtasks.
   150→        }
   151→    }
   152→}
