   154→// ── ActionPopup mode ────────────────────────────────────────────────────────
   155→
   156→/// Handle key events in ActionPopup mode.
   157→///
   158→/// Navigation:
   159→/// - `j` / `Down` — select next action
   160→/// - `k` / `Up` — select previous action
   161→/// - `Enter` — execute the selected action
   162→/// - `Esc` — close the popup, return to Normal mode
   163→fn handle_action_popup(app: &mut App, key: KeyEvent) {
   164→    // Get the action count for the current card's state.
