   216→                            }
   217→                        }
   218→                    }
   219→                }
   220→            }
   221→            app.mode = Mode::Normal;
   222→        }
   223→        KeyCode::Esc => {
   224→            app.mode = Mode::Normal;
   225→        }
   226→        _ => {}
   227→    }
   228→}
