1213→    let mut all_cards: Vec<PathBuf> = Vec::new();
1214→
1215→    for running_dir in running_dirs {
1216→        if !running_dir.exists() {
1217→            continue;
1218→        }
1219→
1220→        let entries = match fs::read_dir(&running_dir) {
1221→            Ok(e) => e,
1222→            Err(_) => continue,
1223→        };
1224→
1225→        let cards: Vec<PathBuf> = entries
1226→            .flatten()
1227→            .filter(|e| {
1228→                let path = e.path();
1229→                path.is_dir() && {
1230→                    let ext = path.extension().and_then(|s| s.to_str());
1231→                    matches!(ext, Some("bop") | Some("jobcard"))
