 18→/// Launch the interactive TUI kanban board.
 19→///
 20→/// Sets up the terminal guard (alternate screen + raw mode), initialises
 21→/// the application state, spawns background event producers, and enters
 22→/// the main event loop. On exit (q or Ctrl-C), the `TerminalGuard`
 23→/// restores the terminal via its `Drop` impl.
 24→pub async fn run_ui(root: &Path) -> anyhow::Result<()> {
 25→    // Initialise application state from the filesystem.
 26→    let mut app = App::new(root)?;
 27→
 28→    // Enter alternate screen + raw mode (restored on Drop).
 29→    let _guard = TerminalGuard::new()?;
 30→
 31→    // Create ratatui terminal with crossterm backend.
 32→    let backend = ratatui::backend::CrosstermBackend::new(io::stdout());
 33→    let mut terminal = Terminal::new(backend)?;
 34→
 35→    // Spawn background tasks: crossterm reader, tick timer, fs watcher.
 36→    let mut events = EventLoop::new(root);
 37→
 38→    // ── Initial render ─────────────────────────────────────────────────
 39→    draw(&mut terminal, &mut app)?;
 40→
 41→    // ── Main event loop ────────────────────────────────────────────────
 42→    loop {
 43→        let Some(event) = events.next().await else {
 44→            break; // all senders dropped — clean shutdown
 45→        };
 46→
 47→        match event {
 48→            AppEvent::Key(key) => {
 49→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
 50→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
 51→                    && key.code == KeyCode::Char('c');
 52→                let quit = app.mode == Mode::Normal && key.code == KeyCode::Char('q');
 53→
 54→                if ctrl_c || quit {
 55→                    break;
 56→                }
 57→
 58→                // Dispatch remaining keys to mode-specific handler.
 59→                input::handle_key(&mut app, key);
 60→            }
 61→            AppEvent::Resize(_w, _h) => {
 62→                // Resize handling will be implemented in subtask 6-4.
 63→            }
 64→            AppEvent::Tick => {
 65→                app.on_tick();
 66→            }
 67→            AppEvent::Cards(columns) => {
 68→                app.refresh_columns(columns);
 69→            }
 70→            AppEvent::LogLine(line) => {
 71→                app.push_log_line(line);
 72→            }
 73→        }
 74→
 75→        // Re-render after every event.
 76→        draw(&mut terminal, &mut app)?;
 77→    }
 78→
 79→    // _guard drops here → restores alternate screen + raw mode.
 80→    Ok(())
 81→}
 82→
 83→/// Render the three-zone layout: header (2 rows), body (remaining), footer (1–2 rows).
 84→///
 85→/// Uses ratatui's `Layout::vertical` to divide the terminal into the
 86→/// k9s-style three-zone layout. The body zone renders the kanban board
 87→/// via [`render_kanban`]; the footer shows context-sensitive keybinding
 88→/// hints via [`render_footer`]. When terminal height > 30, the footer
 89→/// gets 2 rows to display the secondary F-key bar (mc-style).
 90→fn draw(
 91→    terminal: &mut Terminal<ratatui::backend::CrosstermBackend<Stdout>>,
 92→    app: &mut App,
 93→) -> anyhow::Result<()> {
 94→    terminal.draw(|frame| {
 95→        let area = frame.area();
 96→        let terminal_height = area.height;
 97→
 98→        // Footer gets 2 rows when terminal is tall enough for the F-key bar.
 99→        let footer_height = if terminal_height > 30 { 2 } else { 1 };
100→
101→        // Three-zone layout: header (2), body (fill), footer (1–2).
102→        let zones = Layout::vertical([
103→            Constraint::Length(2),
104→            Constraint::Min(0),
105→            Constraint::Length(footer_height),
106→        ])
107→        .split(area);
108→
109→        // ── Header (2 rows) ────────────────────────────────────────────
110→        render_header(frame, zones[0], app);
111→
112→        // ── Body (remaining space) ─────────────────────────────────────
113→        render_kanban(frame, zones[1], app);
114→
115→        // ── Detail overlay (right 50% of body) ────────────────────────
116→        if app.mode == Mode::Detail {
117→            if let Some(card) = app.selected_card().cloned() {
118→                let card_dir = paths::find_card(&app.cards_root, &card.id);
119→                render_detail(
120→                    frame,
121→                    zones[1],
122→                    &card,
123→                    app.detail_scroll,
124→                    card_dir.as_deref(),
125→                );
126→            }
127→        }
128→
129→        // ── LogTail overlay (full body zone) ───────────────────────────
130→        if app.mode == Mode::LogTail {
131→            if let Some(ref card_id) = app.log_tail_card_id.clone() {
132→                render_logtail(
133→                    frame,
134→                    zones[1],
135→                    card_id,
136→                    &app.log_buf,
137→                    app.log_scroll,
138→                    app.log_follow,
139→                );
140→            }
141→        }
142→
143→        // ── Footer (1–2 rows) ──────────────────────────────────────────
144→        render_footer(frame, zones[2], app, terminal_height);
145→    })?;
146→
147→    Ok(())
148→}
