331→/// Direction for navigation movement.
332→enum Direction {
333→    Left,
334→    Right,
335→    Up,
336→    Down,
337→}
338→
339→/// Move column focus left or right, wrapping at boundaries.
340→///
341→/// Skips collapsed (empty) columns — if all columns are collapsed,
342→/// focus stays at index 0.
343→fn move_col_focus(app: &mut App, dir: Direction) {
344→    let len = app.columns.len();
345→    if len == 0 {
346→        return;
347→    }
348→
349→    let step: isize = match dir {
350→        Direction::Left => -1,
351→        Direction::Right => 1,
352→        _ => return,
353→    };
354→
355→    // Try up to `len` positions to find a non-collapsed column.
356→    let mut candidate = app.col_focus as isize;
357→    for _ in 0..len {
358→        candidate = (candidate + step).rem_euclid(len as isize);
359→        let idx = candidate as usize;
360→        if !app.columns[idx].collapsed {
361→            app.col_focus = idx;
362→            return;
363→        }
364→    }
365→
366→    // All columns collapsed — stay where we are.
367→}
