386→        Direction::Up => {
387→            if current == 0 {
388→                card_count - 1
389→            } else {

390→                current - 1
391→            }
392→        }
393→        Direction::Down => {
394→            if current >= card_count - 1 {
395→                0
396→            } else {
397→                current + 1
398→            }
399→        }
400→        _ => return,
401→    };
402→
403→    col.list_state.select(Some(new_idx));
404→}
