    91→// ── Column title ─────────────────────────────────────────────────────────────
    92→
    93→/// Build the column title `Line` with state glyph, name, and count.
    94→///
    95→/// Running columns with a WIP limit show `⚙ RUNNING (N/M)`, with color
    96→/// changing at 75% (amber) and 100% (red) saturation.
    97→fn column_title(col: &KanbanColumn) -> Line<'static> {
    98→    let glyph = state_glyph(&col.state);
