  1→//! jj workspace management for per-card isolation.
  2→//!
  3→//! Each job card gets `jj workspace add <card>/workspace` before the adapter runs.
  4→//! On merge: `jj squash` folds changes back, `jj workspace forget` cleans up.
  5→use anyhow::{Context, Result};
  6→use std::path::Path;
  7→
  8→/// Initialize a jj repo at `repo_root` (colocated with git) if `.jj/` doesn't exist yet.
  9→/// Safe to call repeatedly.
 10→pub fn ensure_jj_repo(repo_root: &Path) -> Result<()> {
 11→    if repo_root.join(".jj").join("repo").exists() {
 12→        return Ok(());
 13→    }
 14→    let out = std::process::Command::new("jj")
 15→        .args(["git", "init", "--colocate"])
 16→        .current_dir(repo_root)
 17→        .output()
 18→        .context("failed to run `jj git init --colocate` (is jj installed?)")?;
 19→    if !out.status.success() {
 20→        let stderr = String::from_utf8_lossy(&out.stderr);
 21→        anyhow::bail!("jj git init failed: {}", stderr);
 22→    }
 23→    Ok(())
 24→}
 25→
 26→/// Create a jj workspace at `ws_path` from `repo_root`.
 27→/// The workspace name is derived from the path basename.
 28→pub fn create_workspace(repo_root: &Path, ws_path: &Path) -> Result<()> {
 29→    let name = ws_path
 30→        .file_name()
 31→        .and_then(|n| n.to_str())
 32→        .with_context(|| {
 33→            format!(
 34→                "workspace path has no usable basename: {}",
 35→                ws_path.display()
 36→            )
 37→        })?;
 38→    create_workspace_with_name(repo_root, ws_path, name)
 39→}
 40→
 41→/// Create a jj workspace at `ws_path` with an explicit workspace name.
 42→pub fn create_workspace_with_name(repo_root: &Path, ws_path: &Path, ws_name: &str) -> Result<()> {
 43→    let out = std::process::Command::new("jj")
 44→        .args(["workspace", "add", "--name", ws_name])
 45→        .arg(ws_path)
 46→        .current_dir(repo_root)
 47→        .output()
 48→        .context("failed to run `jj workspace add`")?;
 49→    if !out.status.success() {
 50→        let stderr = String::from_utf8_lossy(&out.stderr);
 51→        anyhow::bail!("jj workspace add failed: {}", stderr);
 52→    }
 53→    Ok(())
 54→}
