 56→/// Squash all changes in the card workspace into its parent change.
 57→/// Run this from inside the workspace directory after the agent finishes.
 58→pub fn squash_workspace(ws_path: &Path) -> Result<()> {
 59→    let out = std::process::Command::new("jj")
 60→        .args(["squash"])
 61→        .current_dir(ws_path)
 62→        .output()
 63→        .context("failed to run `jj squash`")?;
 64→    if !out.status.success() {
 65→        let stderr = String::from_utf8_lossy(&out.stderr);
 66→        // jj exits non-zero when there are no changes to squash — this is OK.
 67→        // Also accept immutable-root scenarios in fresh repos where there is no
 68→        // parent change to squash into yet.
 69→        if stderr.contains("Nothing changed")
 70→            || (stderr.contains("root commit") && stderr.contains("immutable"))
 71→        {
 72→            return Ok(());
 73→        }
 74→        anyhow::bail!("jj squash failed: {}", stderr);
 75→    }
 76→    Ok(())
 77→}
