 79→/// Forget (deregister) the workspace. Call from repo_root after squashing.
 80→/// jj does not delete the directory — that's the caller's responsibility.
 81→pub fn forget_workspace(repo_root: &Path, ws_name: &str) -> Result<()> {
 82→    // Heal stale working copies before attempting workspace forget.
 83→    let _ = std::process::Command::new("jj")
 84→        .args(["workspace", "update-stale"])
 85→        .current_dir(repo_root)
 86→        .output();
 87→
 88→    let out = std::process::Command::new("jj")
 89→        .args(["workspace", "forget", ws_name])
 90→        .current_dir(repo_root)
 91→        .output()
 92→        .context("failed to run `jj workspace forget`")?;
 93→    if !out.status.success() {
 94→        let stderr = String::from_utf8_lossy(&out.stderr);
 95→        if stderr.contains("no workspace named") || stderr.contains("doesn't have a workspace") {
 96→            return Ok(()); // already forgotten or never existed
 97→        }
 98→        anyhow::bail!("jj workspace forget failed: {}", stderr);
 99→    }
100→    Ok(())
101→}
