103→/// Push all un-pushed changes to the remote as git branches.
104→/// Best-effort: non-fatal if no remote is configured.
105→pub fn push_stack(repo_root: &Path, remote: &str) -> Result<()> {
106→    let out = std::process::Command::new("jj")
107→        .args(["git", "push", "--remote", remote, "--all"])
108→        .current_dir(repo_root)
109→        .output()
110→        .context("failed to run `jj git push`")?;
111→    if !out.status.success() {
112→        let stderr = String::from_utf8_lossy(&out.stderr);
113→        anyhow::bail!("jj git push failed: {}", stderr);
114→    }
115→    Ok(())
116→}
