 21→/// Launch the interactive TUI kanban board.
 22→///
 23→/// Sets up the terminal guard (alternate screen + raw mode), initialises
 24→/// the application state, spawns background event producers, and enters
 25→/// the main event loop. On exit (q or Ctrl-C), the `TerminalGuard`
 26→/// restores the terminal via its `Drop` impl.
 27→pub async fn run_ui(root: &Path) -> anyhow::Result<()> {
 28→    // Initialise application state from the filesystem.
 29→    let mut app = App::new(root)?;
 30→
 31→    // Enter alternate screen + raw mode (restored on Drop).
 32→    let _guard = TerminalGuard::new()?;
 33→
 34→    // Create ratatui terminal with crossterm backend.
 35→    let backend = ratatui::backend::CrosstermBackend::new(io::stdout());
 36→    let mut terminal = Terminal::new(backend)?;
 37→
 38→    // Spawn background tasks: crossterm reader, tick timer, fs watcher.
 39→    let mut events = EventLoop::new(root);
 40→
 41→    // ── Initial render ─────────────────────────────────────────────────
 42→    draw(&mut terminal, &mut app)?;
 43→
 44→    // ── Main event loop ────────────────────────────────────────────────
 45→    loop {
 46→        let Some(event) = events.next().await else {
 47→            break; // all senders dropped — clean shutdown
 48→        };
 49→
 50→        match event {
 51→            AppEvent::Key(key) => {
 52→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
 53→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
 54→                    && key.code == KeyCode::Char('c');
 55→                let quit = app.mode == Mode::Normal && key.code == KeyCode::Char('q');
 56→
 57→                if ctrl_c || quit {
 58→                    break;
 59→                }
 60→
 61→                // Dispatch remaining keys to mode-specific handler.
 62→                input::handle_key(&mut app, key);
 63→
 64→                // If handler requested a subshell, suspend TUI and spawn shell.
 65→                if app.mode == Mode::Subshell {
 66→                    // Leave alternate screen + disable raw mode.
 67→                    let _ = execute!(io::stdout(), cursor::Show, LeaveAlternateScreen);
 68→                    let _ = disable_raw_mode();
 69→
 70→                    // Run the subshell synchronously (blocks until shell exits).
 71→                    app.run_subshell();
 72→
 73→                    // Re-enter alternate screen + raw mode.
 74→                    let _ = enable_raw_mode();
 75→                    let _ = execute!(io::stdout(), EnterAlternateScreen, cursor::Hide);
 76→
 77→                    // Force full redraw by clearing the terminal's back buffer.
 78→                    let _ = terminal.clear();
 79→                }
 80→            }
 81→            AppEvent::Resize(_w, _h) => {
 82→                // Resize handling will be implemented in subtask 6-4.
 83→            }
 84→            AppEvent::Tick => {
 85→                app.on_tick();
 86→            }
 87→            AppEvent::Cards(columns) => {
 88→                app.refresh_columns(columns);
 89→            }
 90→            AppEvent::LogLine(line) => {
 91→                app.push_log_line(line);
 92→            }
 93→        }
 94→
 95→        // Re-render after every event.
 96→        draw(&mut terminal, &mut app)?;
 97→    }
 98→
 99→    // _guard drops here → restores alternate screen + raw mode.
100→    Ok(())
101→}
