103→/// Render the three-zone layout: header (2 rows), body (remaining), footer (1–2 rows).
104→///
105→/// Uses ratatui's `Layout::vertical` to divide the terminal into the
106→/// k9s-style three-zone layout. The body zone renders the kanban board
107→/// via [`render_kanban`]; the footer shows context-sensitive keybinding
108→/// hints via [`render_footer`]. When terminal height > 30, the footer
109→/// gets 2 rows to display the secondary F-key bar (mc-style).
110→fn draw(
111→    terminal: &mut Terminal<ratatui::backend::CrosstermBackend<Stdout>>,
112→    app: &mut App,
113→) -> anyhow::Result<()> {
114→    terminal.draw(|frame| {
115→        let area = frame.area();
116→        let terminal_height = area.height;
117→
118→        // Footer gets 2 rows when terminal is tall enough for the F-key bar.
119→        let footer_height = if terminal_height > 30 { 2 } else { 1 };
120→
121→        // Three-zone layout: header (2), body (fill), footer (1–2).
122→        let zones = Layout::vertical([
123→            Constraint::Length(2),
124→            Constraint::Min(0),
125→            Constraint::Length(footer_height),
126→        ])
127→        .split(area);
128→
129→        // ── Header (2 rows) ────────────────────────────────────────────
130→        render_header(frame, zones[0], app);
131→
132→        // ── Body (remaining space) ─────────────────────────────────────
133→        render_kanban(frame, zones[1], app);
134→
135→        // ── Detail overlay (right 50% of body) ────────────────────────
136→        if app.mode == Mode::Detail {
137→            if let Some(card) = app.selected_card().cloned() {
138→                let card_dir = paths::find_card(&app.cards_root, &card.id);
139→                render_detail(
140→                    frame,
141→                    zones[1],
142→                    &card,
143→                    app.detail_scroll,
144→                    card_dir.as_deref(),
145→                );
146→            }
147→        }
148→
149→        // ── LogTail overlay (full body zone) ───────────────────────────
150→        if app.mode == Mode::LogTail {
151→            if let Some(ref card_id) = app.log_tail_card_id.clone() {
152→                render_logtail(
153→                    frame,
154→                    zones[1],
155→                    card_id,
156→                    &app.log_buf,
157→                    app.log_scroll,
158→                    app.log_follow,
159→                );
160→            }
161→        }
162→
163→        // ── Footer (1–2 rows) ──────────────────────────────────────────
164→        render_footer(frame, zones[2], app, terminal_height);
165→    })?;
166→
167→    Ok(())
168→}
