   173→fn card_to_list_item(
   174→    card: &CardView,
   175→    filter_match: Option<&FilterMatch>,
   176→    is_marked: bool,
   177→) -> ListItem<'static> {
   178→    let color = state_ratatui_color(&card.state);
   179→
   180→    // Use BMP-safe token if available, then glyph, then state marker.
   181→    let display_marker = card
   182→        .token
   183→        .as_deref()
   184→        .or(card.glyph.as_deref())
   185→        .unwrap_or(card_marker(&card.state));
   186→
   187→    // First line: mark indicator + marker + highlighted title + provider + elapsed.
   188→    let mut spans = Vec::new();
   189→
   190→    // Mark indicator prefix (yazi pattern: ■ for marked cards).
   191→    if is_marked {
   192→        spans.push(Span::styled(
   193→            "■ ".to_string(),
   194→            Style::default().fg(Color::Cyan),
   195→        ));
   196→    }
   197→
   198→    spans.push(Span::styled(
   199→        format!("{} ", display_marker),
   200→        Style::default().fg(color),
   201→    ));
