    24→/// Launch the interactive TUI kanban board.
    25→///
    26→/// Sets up the terminal guard (alternate screen + raw mode), initialises
    27→/// the application state, spawns background event producers, and enters
    28→/// the main event loop. On exit (q or Ctrl-C), the `TerminalGuard`
    29→/// restores the terminal via its `Drop` impl.
    30→pub async fn run_ui(root: &Path) -> anyhow::Result<()> {
    31→    // Initialise application state from the filesystem.
    32→    let mut app = App::new(root)?;
    33→
    34→    // Enter alternate screen + raw mode (restored on Drop).
    35→    let _guard = TerminalGuard::new()?;
    36→
    37→    // Create ratatui terminal with crossterm backend.
    38→    let backend = ratatui::backend::CrosstermBackend::new(io::stdout());
    39→    let mut terminal = Terminal::new(backend)?;
    40→
    41→    // Spawn background tasks: crossterm reader, tick timer, fs watcher.
    42→    let mut events = EventLoop::new(root);
    43→
    44→    // ── Initial render ─────────────────────────────────────────────────
    45→    draw(&mut terminal, &mut app)?;
    46→
    47→    // ── Main event loop ────────────────────────────────────────────────
    48→    loop {
    49→        let Some(event) = events.next().await else {
    50→            break; // all senders dropped — clean shutdown
    51→        };
    52→
    53→        match event {
    54→            AppEvent::Key(key) => {
    55→                // Quit on 'q' (Normal mode) or Ctrl-C (any mode).
    56→                let ctrl_c = key.modifiers.contains(KeyModifiers::CONTROL)
    57→                    && key.code == KeyCode::Char('c');
    58→                let quit = app.mode == Mode::Normal && key.code == KeyCode::Char('q');
    59→
    60→                if ctrl_c || quit {
    61→                    break;
    62→                }
    63→
    64→                // Dispatch remaining keys to mode-specific handler.
    65→                input::handle_key(&mut app, key);
    66→
    67→                // If handler requested a subshell, suspend TUI and spawn shell.
    68→                if app.mode == Mode::Subshell {
    69→                    // Leave alternate screen + disable raw mode.
    70→                    let _ = execute!(io::stdout(), cursor::Show, LeaveAlternateScreen);
    71→                    let _ = disable_raw_mode();
    72→
    73→                    // Run the subshell synchronously (blocks until shell exits).
    74→                    app.run_subshell();
    75→
    76→                    // Re-enter alternate screen + raw mode.
    77→                    let _ = enable_raw_mode();
    78→                    let _ = execute!(io::stdout(), EnterAlternateScreen, cursor::Hide);
    79→
    80→                    // Force full redraw by clearing the terminal's back buffer.
    81→                    let _ = terminal.clear();
    82→                }
    83→            }
    84→            AppEvent::Resize(w, h) => {
    85→                app.on_resize(w, h);
    86→            }
    87→            AppEvent::Tick => {
    88→                app.on_tick();
    89→            }
    90→            AppEvent::Cards(columns) => {
    91→                app.refresh_columns(columns);
    92→            }
    93→            AppEvent::LogLine(line) => {
    94→                app.push_log_line(line);
    95→            }
    96→        }
    97→
    98→        // Re-render after every event.
    99→        draw(&mut terminal, &mut app)?;
   100→    }
   101→
   102→    // _guard drops here → restores alternate screen + raw mode.
   103→    Ok(())
   104→}
