   106→/// Render the three-zone layout: header (2 rows), body (remaining), footer (1–2 rows).
   107→///
   108→/// Uses ratatui's `Layout::vertical` to divide the terminal into the
   109→/// k9s-style three-zone layout. The body zone renders the kanban board
   110→/// via [`render_kanban`]; the footer shows context-sensitive keybinding
   111→/// hints via [`render_footer`]. When terminal height > 30, the footer
   112→/// gets 2 rows to display the secondary F-key bar (mc-style).
   113→///
   114→/// When terminal height < 10, renders a minimal single-line status bar
   115→/// instead of the full TUI to remain usable in very small terminals.
   116→fn draw(
   117→    terminal: &mut Terminal<ratatui::backend::CrosstermBackend<Stdout>>,
   118→    app: &mut App,
   119→) -> anyhow::Result<()> {
   120→    terminal.draw(|frame| {
   121→        let area = frame.area();
   122→        let terminal_height = area.height;
   123→
   124→        // Update stored dimensions from the actual frame area.
   125→        app.terminal_width = area.width;
   126→        app.terminal_height = terminal_height;
   127→
   128→        // ── Minimal mode: single-line status when terminal too short ──
   129→        if app.is_minimal_height() {
   130→            render_minimal_status(frame, area, app);
   131→            return;
   132→        }
   133→
   134→        // Footer gets 2 rows when terminal is tall enough for the F-key bar.
   135→        let footer_height = if terminal_height > 30 { 2 } else { 1 };
   136→
   137→        // Three-zone layout: header (2), body (fill), footer (1–2).
   138→        let zones = Layout::vertical([
   139→            Constraint::Length(2),
   140→            Constraint::Min(0),
   141→            Constraint::Length(footer_height),
   142→        ])
   143→        .split(area);
   144→
   145→        // ── Header (2 rows) ────────────────────────────────────────────
   146→        render_header(frame, zones[0], app);
   147→
   148→        // ── Body (remaining space) ─────────────────────────────────────
   149→        render_kanban(frame, zones[1], app);
   150→
   151→        // ── Detail overlay (right 50% of body) ────────────────────────
   152→        if app.mode == Mode::Detail {
   153→            if let Some(card) = app.selected_card().cloned() {
   154→                let card_dir = paths::find_card(&app.cards_root, &card.id);
   155→                render_detail(
   156→                    frame,
   157→                    zones[1],
   158→                    &card,
   159→                    app.detail_scroll,
   160→                    card_dir.as_deref(),
   161→                );
   162→            }
   163→        }
   164→
   165→        // ── LogTail overlay (full body zone) ───────────────────────────
   166→        if app.mode == Mode::LogTail {
   167→            if let Some(ref card_id) = app.log_tail_card_id.clone() {
   168→                render_logtail(
   169→                    frame,
   170→                    zones[1],
   171→                    card_id,
   172→                    &app.log_buf,
   173→                    app.log_scroll,
   174→                    app.log_follow,
   175→                );
   176→            }
   177→        }
   178→
   179→        // ── Footer (1–2 rows) ──────────────────────────────────────────
   180→        render_footer(frame, zones[2], app, terminal_height);
   181→    })?;
   182→
   183→    Ok(())
   184→}
