   198→pub fn quarantine_invalid_pending_card(
   199→    pending_path: &Path,
   200→    failed_dir: &Path,
   201→    reason: &str,
   202→) -> anyhow::Result<()> {
   203→    let name = pending_path
   204→        .file_name()
   205→        .and_then(|n| n.to_str())
   206→        .with_context(|| format!("invalid card path: {}", pending_path.display()))?;
   207→    let failed_path = util::unique_failed_path(failed_dir, name);
   208→    fs::rename(pending_path, &failed_path).with_context(|| {
   209→        format!(
   210→            "failed moving invalid pending card {} to failed/",
   211→            pending_path.display()
   212→        )
   213→    })?;
   214→    fs::create_dir_all(failed_path.join("logs"))?;
   215→    fs::create_dir_all(failed_path.join("output"))?;
   216→    let marker = format!("[{}] dispatcher rejected card: {}\n", Utc::now(), reason);
   217→    util::append_log_line(
   218→        &failed_path.join("logs").join("rejected.log"),
   219→        marker.trim_end(),
   220→    )?;
   221→    let _ = fs::write(failed_path.join("output").join("qa_report.md"), marker);
   222→    quicklook::render_card_thumbnail(&failed_path);
   223→    Ok(())
   224→}
