    25→// ── Glyph helpers ────────────────────────────────────────────────────────────
    26→
    27→/// State glyph for column headers and collapsed dividers.
    28→///
    29→/// Matches the spec's visual language: `·` pending, `⚙` running,
    30→/// `✓` done, `✗` failed, `~` merged.
    31→fn state_glyph(state: &str) -> &'static str {
    32→    match state {
    33→        "pending" => "·",
    34→        "running" => "⚙",
    35→        "done" => "✓",
    36→        "failed" => "✗",
    37→        "merged" => "~",
    38→        _ => "?",
    39→    }
    40→}
    41→
    42→/// Card marker glyph for list rows (matches render/full.rs pattern).
    43→fn card_marker(state: &str) -> &'static str {
    44→    match state {
    45→        "running" => "▶",
    46→        "done" | "merged" => "✓",
    47→        "failed" => "✗",
    48→        _ => "·",
    49→    }
    50→}
    51→
    52→/// RGB color for a given state (matches colors.rs hex values).
    53→///
    54→/// Uses 24-bit RGB for consistent appearance across terminals that
    55→/// support truecolor (which ratatui auto-detects).
    56→fn state_ratatui_color(state: &str) -> Color {
    57→    match state {
    58→        "pending" => Color::Rgb(0x3A, 0x5A, 0x8A),
    59→        "running" => Color::Rgb(0xB8, 0x69, 0x0F),
    60→        "done" => Color::Rgb(0x1E, 0x8A, 0x45),
    61→        "failed" => Color::Rgb(0xC4, 0x30, 0x30),
    62→        "merged" => Color::Rgb(0x6B, 0x3D, 0xB8),
    63→        _ => Color::Gray,
    64→    }
    65→}
    66→
    67→/// Moon-quarter glyph for phase progress (matches render/full.rs).
    68→///
    69→/// ◔ (< 25%), ◑ (25–50%), ◕ (50–75%), ● (≥ 75%).
    70→fn moon_glyph(frac: f32) -> char {
    71→    if frac < 0.25 {
    72→        '◔'
    73→    } else if frac < 0.50 {
    74→        '◑'
    75→    } else if frac < 0.75 {
    76→        '◕'
    77→    } else {
    78→        '●'
    79→    }
    80→}
    81→
    82→/// Format seconds into human-readable "XmYYs" or "Xs" (matches render/full.rs).
    83→fn format_duration(secs: u64) -> String {
    84→    if secs >= 60 {
    85→        format!("{}m{:02}s", secs / 60, secs % 60)
    86→    } else {
    87→        format!("{}s", secs)
    88→    }
    89→}
    90→
    91→// ── Column title ─────────────────────────────────────────────────────────────
    92→
    93→/// Build the column title `Line` with state glyph, name, and count.
    94→///
    95→/// Running columns with a WIP limit show `⚙ RUNNING (N/M)`, with color
    96→/// changing at 75% (amber) and 100% (red) saturation.
    97→fn column_title(col: &KanbanColumn) -> Line<'static> {
    98→    let glyph = state_glyph(&col.state);
    99→    let name = col.state.to_uppercase();
   100→    let count = col.cards.len();
   101→
   102→    let title_text = if col.state == "running" {
   103→        if let Some(limit) = col.wip_limit {
   104→            format!(" {} {} ({}/{}) ", glyph, name, count, limit)
   105→        } else {
   106→            format!(" {} {} ({}) ", glyph, name, count)
   107→        }
   108→    } else {
   109→        format!(" {} {} ({}) ", glyph, name, count)
   110→    };
   111→
   112→    let color = title_color(col);
   113→    Line::from(Span::styled(
   114→        title_text,
   115→        Style::default().fg(color).add_modifier(Modifier::BOLD),
   116→    ))
   117→}
   118→
   119→/// Determine title color based on state and WIP saturation.
   120→///
   121→/// Running column with WIP limit: amber at ≥75%, red at 100%.
   122→/// All other columns use their default state color.
   123→fn title_color(col: &KanbanColumn) -> Color {
   124→    if col.state == "running" && col.wip_limit.is_some() {
   125→        let sat = col.wip_saturation();
   126→        if sat >= 1.0 {
   127→            Color::Red
   128→        } else if sat >= 0.75 {
   129→            Color::Yellow
   130→        } else {
   131→            state_ratatui_color(&col.state)
   132→        }
   133→    } else {
   134→        state_ratatui_color(&col.state)
   135→    }
   136→}
   137→
   138→/// Determine border color for a column.
   139→///
   140→/// Priority: running at 100% WIP → red (even if focused), focused → yellow,
   141→/// running ≥75% → amber, default → dark gray.
   142→fn border_color(col: &KanbanColumn, is_focused: bool) -> Color {
   143→    if col.state == "running" && col.wip_limit.is_some() {
   144→        let sat = col.wip_saturation();
   145→        if sat >= 1.0 {
   146→            return Color::Red;
   147→        } else if sat >= 0.75 {
   148→            return Color::Yellow;
   149→        }
   150→    }
   151→
   152→    if is_focused {
   153→        Color::Yellow
   154→    } else {
   155→        Color::DarkGray
   156→    }
   157→}
