  1→/// Nucleo-powered fuzzy filter for the kanban board.
  2→///
  3→/// When the user presses `/` in Normal mode, the TUI enters `Mode::Filter`.
  4→/// Each keystroke updates the nucleo pattern and filters all cards across
  5→/// all columns by matching `card.id + " " + card.title`. Columns with no
  6→/// matches after filtering collapse to narrow dividers. Matched characters
  7→/// are highlighted in card titles with `Color::Yellow` + `BOLD` using
  8→/// nucleo's match indices.
  9→///
 10→/// - `Esc` clears the filter and restores full columns.
 11→/// - `Enter` confirms the filter (stays in Normal with filter active).
 12→use nucleo::pattern::{AtomKind, CaseMatching, Normalization, Pattern};
 13→use nucleo::{Matcher, Utf32String};
 14→
 15→/// Result of matching a single card against the current filter pattern.
 16→#[derive(Debug, Clone)]
 17→pub struct FilterMatch {
 18→    /// Indices into the card title string that matched (sorted, deduplicated).
 19→    /// Used for highlight rendering in the kanban widget.
 20→    pub title_indices: Vec<u32>,
 21→}
 22→
 23→/// Shared filter state held by [`App`](crate::ui::app::App).
 24→///
 25→/// Created when entering Filter mode, updated on each keystroke, and
 26→/// dropped when the filter is cleared. The `Matcher` is reused across
 27→/// keystrokes to avoid repeated allocation.
 28→pub struct FilterState {
 29→    /// The current query string being typed by the user.
 30→    pub query: String,
 31→    /// Reusable nucleo matcher instance.
 32→    matcher: Matcher,
 33→}
 34→
 35→impl FilterState {
 36→    /// Create a new empty filter state with a default matcher.
 37→    pub fn new() -> Self {
 38→        Self {
 39→            query: String::new(),
 40→            matcher: Matcher::new(nucleo::Config::DEFAULT),
 41→        }
 42→    }
 43→
 44→    /// Test whether a card matches the current query.
 45→    ///
 46→    /// Matches against `"{id} {title}"` — the combined haystack gives
 47→    /// users flexibility to filter by either card ID or title text.
 48→    /// Returns `None` if no match; returns `Some(FilterMatch)` with
 49→    /// highlighted indices into the *title* portion on match.
 50→    ///
 51→    /// When the query is empty, all cards match (with no highlights).
 52→    pub fn matches(&mut self, card_id: &str, card_title: &str) -> Option<FilterMatch> {
 53→        if self.query.is_empty() {
 54→            return Some(FilterMatch {
 55→                title_indices: Vec::new(),
 56→            });
 57→        }
 58→
 59→        let pattern = Pattern::new(
 60→            &self.query,
 61→            CaseMatching::Smart,
 62→            Normalization::Smart,
 63→            AtomKind::Fuzzy,
 64→        );
 65→
 66→        // Build combined haystack: "id title"
 67→        let haystack_str = format!("{} {}", card_id, card_title);
 68→        let haystack = Utf32String::from(haystack_str.as_str());
 69→
 70→        // Check if the pattern matches the combined haystack.
 71→        let mut indices: Vec<u32> = Vec::new();
 72→        let score = pattern.indices(haystack.slice(..), &mut self.matcher, &mut indices);
 73→
 74→        if score.is_none() {
 75→            return None;
 76→        }
 77→
 78→        indices.sort_unstable();
 79→        indices.dedup();
 80→
 81→        // Convert combined-haystack indices to title-only indices.
 82→        // The title starts at byte offset (id.len() + 1) in the combined string,
 83→        // but nucleo indices are char indices, so we need the char offset.
 84→        let id_char_len = card_id.chars().count() as u32;
 85→        let title_offset = id_char_len + 1; // +1 for the space separator
 86→
 87→        let title_indices: Vec<u32> = indices
 88→            .into_iter()
 89→            .filter_map(|idx| {
 90→                if idx >= title_offset {
 91→                    Some(idx - title_offset)
 92→                } else {
 93→                    None
 94→                }
 95→            })
 96→            .collect();
 97→
 98→        Some(FilterMatch { title_indices })
 99→    }
100→}
