  1→/// Log tail overlay widget — full-height scrollable log view.
  2→///
  3→/// Replaces the body zone when `Mode::LogTail` is active. Shows the last
  4→/// 200 lines from the selected card's `logs/stdout.log` and
  5→/// `logs/stderr.log`. Implements newline-gated streaming: bytes are
  6→/// buffered and only complete lines (ending in `\n`) are emitted to
  7→/// prevent partial ANSI sequence flicker.
  8→///
  9→/// Keybindings (handled in `input.rs`):
 10→/// - `↑` / `↓` — scroll up / down
 11→/// - `f` — toggle follow mode (auto-scroll to bottom)
 12→/// - `c` — clear buffer
 13→/// - `Esc` — return to Normal mode
 14→use std::collections::VecDeque;
 15→
 16→use ratatui::layout::Rect;
 17→use ratatui::style::{Color, Modifier, Style};
 18→use ratatui::text::{Line, Span};
 19→use ratatui::widgets::{Block, Clear, Paragraph, Wrap};
 20→use ratatui::Frame;
 21→
 22→// ── Line styling ────────────────────────────────────────────────────────────
 23→
 24→/// Stylize a single log line for TUI display using ratatui `Style`.
 25→///
 26→/// Mirrors the colorization logic from `logs.rs::colorize_log_line` but
 27→/// uses ratatui styles instead of raw ANSI escape codes, since the TUI
 28→/// owns all terminal rendering via ratatui.
 29→fn stylize_log_line(line: &str) -> Line<'static> {
 30→    let style = if line.contains("ERROR") || line.contains("error:") || line.contains("FAILED") {
 31→        Style::default()
 32→            .fg(Color::Red)
 33→            .add_modifier(Modifier::BOLD)
 34→    } else if line.contains("WARN") || line.contains("warning:") {
 35→        Style::default().fg(Color::Yellow)
 36→    } else if line.contains("INFO") {
 37→        Style::default().fg(Color::Cyan)
 38→    } else if line.contains("DEBUG") || line.contains("TRACE") {
 39→        Style::default().fg(Color::DarkGray)
 40→    } else if line.contains("→ merged") || line.contains("-> merged") {
 41→        Style::default()
 42→            .fg(Color::Magenta)
 43→            .add_modifier(Modifier::BOLD)
 44→    } else if line.contains("→ done") || line.contains("-> done") {
 45→        Style::default()
 46→            .fg(Color::Green)
 47→            .add_modifier(Modifier::BOLD)
 48→    } else if line.contains("→ failed") || line.contains("-> failed") {
 49→        Style::default()
 50→            .fg(Color::Red)
 51→            .add_modifier(Modifier::BOLD)
 52→    } else if line.contains("→ running") || line.contains("-> running") {
 53→        Style::default()
 54→            .fg(Color::Yellow)
 55→            .add_modifier(Modifier::BOLD)
 56→    } else {
 57→        Style::default().fg(Color::White)
 58→    };
 59→
 60→    Line::from(Span::styled(line.to_string(), style))
 61→}
 62→
 63→// ── Public render function ──────────────────────────────────────────────────
 64→
 65→/// Render the log tail overlay, replacing the full body zone.
 66→///
 67→/// Draws a bordered block with the card ID in the title, a follow-mode
 68→/// indicator, and the buffered log lines with scroll support. When
 69→/// `follow_mode` is enabled, the scroll offset is automatically computed
 70→/// to show the most recent lines at the bottom of the viewport.
 71→///
 72→/// The overlay uses ratatui `Clear` to erase the underlying kanban board
 73→/// content before rendering the log view.
 74→pub fn render_logtail(
 75→    frame: &mut Frame,
 76→    body_area: Rect,
 77→    card_id: &str,
 78→    log_buf: &VecDeque<String>,
 79→    log_scroll: usize,
 80→    follow_mode: bool,
 81→) {
 82→    // Clear the entire body area so the kanban content is hidden.
 83→    frame.render_widget(Clear, body_area);
 84→
 85→    // Build title with follow-mode indicator.
 86→    let follow_indicator = if follow_mode { " [FOLLOW]" } else { "" };
 87→    let title = format!(" {} — logs{} ", card_id, follow_indicator);
 88→
 89→    let title_style = if follow_mode {
 90→        Style::default()
 91→            .fg(Color::Green)
 92→            .add_modifier(Modifier::BOLD)
 93→    } else {
 94→        Style::default()
 95→            .fg(Color::Yellow)
 96→            .add_modifier(Modifier::BOLD)
 97→    };
 98→
 99→    let block = Block::bordered()
100→        .title(title)
101→        .title_style(title_style)
102→        .border_style(Style::default().fg(Color::Yellow));
103→
104→    // Stylize each line from the circular buffer.
105→    let lines: Vec<Line> = log_buf.iter().map(|l| stylize_log_line(l)).collect();
106→
107→    // Calculate effective scroll offset.
108→    // In follow mode, auto-scroll to show the latest lines at the bottom.
109→    let visible_height = body_area.height.saturating_sub(2) as usize; // minus top/bottom borders
110→    let effective_scroll = if follow_mode {
111→        lines.len().saturating_sub(visible_height)
112→    } else {
113→        log_scroll
114→    };
115→
116→    let paragraph = Paragraph::new(lines)
117→        .block(block)
118→        .wrap(Wrap { trim: false })
119→        .scroll((effective_scroll as u16, 0));
120→
121→    frame.render_widget(paragraph, body_area);
122→}
