   108→
   109→/// Render the action popup overlay centered in the given body area.
   110→///
   111→/// Uses ratatui `Clear` to erase the underlying kanban content, then draws
   112→/// a bordered `Block` with a selectable `List` of state-filtered actions.
   113→///
   114→/// The popup is sized to fit the action list: width is clamped between
   115→/// 30 and 50 characters, height is the action count + 2 (for borders).
   116→pub fn render_action_popup(
   117→    frame: &mut Frame,
   118→    body_area: Rect,
   119→    card_state: &str,
   120→    card_id: &str,
   121→    action_list_state: &mut ListState,
   122→) {
   123→    let actions = actions_for_state(card_state);
   124→
   125→    if actions.is_empty() {
   126→        // No actions available — render a small "no actions" popup.
   127→        render_empty_popup(frame, body_area, card_id);
   128→        return;
   129→    }
   130→
   131→    // Popup dimensions.
   132→    let popup_width = 36u16.min(body_area.width.saturating_sub(4));
   133→    let popup_height = (actions.len() as u16 + 2).min(body_area.height.saturating_sub(2));
   134→
   135→    let popup_area = centered_rect(popup_width, popup_height, body_area);
   136→
   137→    // Clear the underlying content.
   138→    frame.render_widget(Clear, popup_area);
   139→
   140→    // Build the bordered block with title.
   141→    let title = format!(" {} ", card_id);
   142→    let block = Block::bordered()
   143→        .title(title)
   144→        .title_style(
   145→            Style::default()
   146→                .fg(Color::Yellow)
   147→                .add_modifier(Modifier::BOLD),
   148→        )
   149→        .border_style(Style::default().fg(Color::Yellow));
   150→
   151→    // Build list items from actions.
   152→    let items: Vec<ListItem> = actions
   153→        .iter()
   154→        .map(|action| {
   155→            let line = Line::from(vec![
   156→                Span::styled(
   157→                    format!("{} ", action.key_hint),
   158→                    Style::default().fg(Color::Cyan),
   159→                ),
   160→                Span::styled(action.label, Style::default().fg(Color::White)),
   161→            ]);
   162→            ListItem::new(line)
   163→        })
   164→        .collect();
   165→
   166→    let list = List::new(items)
   167→        .block(block)
   168→        .highlight_style(
   169→            Style::default()
   170→                .fg(Color::Yellow)
   171→                .add_modifier(Modifier::BOLD),
   172→        )
   173→        .highlight_symbol("▸ ");
   174→
   175→    frame.render_stateful_widget(list, popup_area, action_list_state);
   176→}
   177→
   178→/// Render a small popup indicating no actions are available.
   179→fn render_empty_popup(frame: &mut Frame, body_area: Rect, card_id: &str) {
   180→    let popup_width = 30u16.min(body_area.width.saturating_sub(4));
   181→    let popup_height = 3u16.min(body_area.height.saturating_sub(2));
   182→
   183→    let popup_area = centered_rect(popup_width, popup_height, body_area);
   184→    frame.render_widget(Clear, popup_area);
   185→
   186→    let title = format!(" {} ", card_id);
   187→    let block = Block::bordered()
   188→        .title(title)
   189→        .title_style(
   190→            Style::default()
   191→                .fg(Color::DarkGray)
   192→                .add_modifier(Modifier::BOLD),
   193→        )
   194→        .border_style(Style::default().fg(Color::DarkGray));
   195→
   196→    let paragraph = ratatui::widgets::Paragraph::new(Line::from(Span::styled(
   197→        "no actions available",
   198→        Style::default().fg(Color::DarkGray),
   199→    )))
   200→    .block(block);
   201→
   202→    frame.render_widget(paragraph, popup_area);
   203→}
   204→
   205→/// Compute a centered `Rect` of the given width and height within `area`.
   206→fn centered_rect(width: u16, height: u16, area: Rect) -> Rect {
   207→    let x = area.x + (area.width.saturating_sub(width)) / 2;
   208→    let y = area.y + (area.height.saturating_sub(height)) / 2;
   209→    Rect::new(x, y, width.min(area.width), height.min(area.height))
   210→}
