     1→/// Header bar widget — top 2 rows of the three-zone TUI layout.
     2→///
     3→/// Line 1: `bop · HH:MM:SS · {provider meters} · {sparkline} N/hr`
     4→/// Line 2 (width ≥ 120): scrolling event ticker of recent card completions.
     5→///
     6→/// Provider meters show one bar per provider from `providers.json`, colored:
     7→/// - Green: available
     8→/// - Amber: busy (has a running card)
     9→/// - Red: rate-limited / in cooldown
    10→///
    11→/// Sparkline uses last 8 throughput samples: ▁▂▃▄▅▆▇█
    12→use chrono::Local;
    13→use ratatui::layout::Rect;
    14→use ratatui::style::{Color, Style};
    15→use ratatui::text::{Line, Span};
    16→use ratatui::widgets::Paragraph;
    17→use ratatui::Frame;
    18→
    19→use crate::ui::app::App;
    20→
    21→// ── Provider status ─────────────────────────────────────────────────────────
    22→
    23→/// Provider status for header bar meters.
    24→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    25→pub enum ProviderStatus {
    26→    /// Provider is available (green).
    27→    Available,
    28→    /// Provider has a running card (amber).
    29→    Busy,
    30→    /// Provider is rate-limited or in cooldown (red).
    31→    RateLimited,
    32→}
    33→
    34→/// One entry in the provider meter bar.
    35→#[derive(Debug, Clone)]
    36→pub struct ProviderMeter {
    37→    pub name: String,
    38→    pub status: ProviderStatus,
    39→}
    40→
    41→// ── Colors ──────────────────────────────────────────────────────────────────
    42→
    43→/// Color for a provider meter based on status.
    44→fn meter_color(status: ProviderStatus) -> Color {
    45→    match status {
    46→        ProviderStatus::Available => Color::Green,
    47→        ProviderStatus::Busy => Color::Yellow,
    48→        ProviderStatus::RateLimited => Color::Red,
    49→    }
    50→}
    51→
    52→// ── Sparkline ───────────────────────────────────────────────────────────────
    53→
    54→/// Sparkline block characters ordered by magnitude (index 0 = lowest).
    55→const SPARK_CHARS: [char; 8] = ['▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
    56→
    57→/// Convert a throughput value to a sparkline character.
    58→///
    59→/// Maps `value` into the 0–7 range based on `max_val`. If `max_val` is 0
    60→/// all values map to the lowest bar (▁).
    61→fn spark_char(value: u8, max_val: u8) -> char {
    62→    if max_val == 0 {
    63→        return SPARK_CHARS[0];
    64→    }
    65→    let idx = ((value as usize) * 7) / (max_val as usize);
    66→    SPARK_CHARS[idx.min(7)]
    67→}
    68→
    69→/// Build a sparkline string from a slice of throughput samples.
    70→fn build_sparkline(samples: &[u8]) -> String {
    71→    let max_val = samples.iter().copied().max().unwrap_or(0);
    72→    samples.iter().map(|&v| spark_char(v, max_val)).collect()
    73→}
    74→
    75→// ── Provider meter bar ──────────────────────────────────────────────────────
    76→
    77→/// Width of each provider meter in block characters.
    78→const METER_WIDTH: usize = 4;
    79→
    80→/// Build Spans for all provider meters.
    81→///
    82→/// Each provider gets `METER_WIDTH` block chars: filled (█) in the
    83→/// provider's status color, followed by empty (░) in dark gray to fill
    84→/// any remaining width. Since each meter is binary (status indicator,
    85→/// not a gauge), we fill all blocks in the status color.
    86→fn build_meter_spans(meters: &[ProviderMeter]) -> Vec<Span<'static>> {
    87→    let mut spans = Vec::new();
    88→    for (i, meter) in meters.iter().enumerate() {
    89→        if i > 0 {
    90→            spans.push(Span::raw(" "));
    91→        }
    92→        let color = meter_color(meter.status);
    93→        let filled = "█".repeat(METER_WIDTH);
    94→        spans.push(Span::styled(filled, Style::default().fg(color)));
    95→    }
    96→    spans
    97→}
    98→
    99→// ── Event ticker ────────────────────────────────────────────────────────────
   100→
   101→/// Maximum number of recent completions stored for the event ticker.
   102→pub const TICKER_CAPACITY: usize = 20;
   103→
   104→/// Separator between ticker entries.
   105→const TICKER_SEP: &str = "  ·  ";
   106→
   107→/// Build the scrolling event ticker string from recent completions.
   108→///
   109→/// Joins all entries with a separator, then uses `tick_offset` to scroll
   110→/// the text left across the available width (demoscene-style marquee).
   111→fn build_ticker_text(completions: &[String], tick_offset: usize, width: usize) -> String {
   112→    if completions.is_empty() || width == 0 {
   113→        return String::new();
   114→    }
   115→
   116→    let joined = completions.join(TICKER_SEP);
   117→    if joined.is_empty() {
   118→        return String::new();
   119→    }
   120→
   121→    // Create a repeating buffer so the scroll wraps smoothly.
   122→    let padded = format!("{}{}{}", joined, TICKER_SEP, joined);
   123→    let total_len = padded.chars().count();
   124→    let offset = tick_offset % total_len;
   125→
   126→    padded
   127→        .chars()
   128→        .cycle()
   129→        .skip(offset)
   130→        .take(width)
   131→        .collect()
   132→}
   133→
   134→// ── Main render ─────────────────────────────────────────────────────────────
   135→
   136→/// Render the header bar into the given area.
   137→///
   138→/// Uses the first row for the main status line and the second row for
   139→/// the scrolling event ticker (only if terminal width ≥ 120).
   140→pub fn render_header(frame: &mut Frame, area: Rect, app: &App) {
   141→    if area.height == 0 || area.width == 0 {
   142→        return;
   143→    }
   144→
   145→    let width = area.width as usize;
   146→
   147→    // ── Line 1: bop · HH:MM:SS · meters · sparkline N/hr ──────────
   148→    let time_str = Local::now().format("%H:%M:%S").to_string();
   149→
   150→    let mut spans: Vec<Span<'static>> = vec![
   151→        Span::styled("bop", Style::default().fg(Color::Cyan)),
   152→        Span::styled(" · ", Style::default().fg(Color::DarkGray)),
   153→        Span::styled(time_str, Style::default().fg(Color::White)),
   154→    ];
   155→
   156→    // Provider meters.
   157→    if !app.provider_meters.is_empty() {
   158→        spans.push(Span::styled(" · ", Style::default().fg(Color::DarkGray)));
   159→        spans.extend(build_meter_spans(&app.provider_meters));
   160→    }
   161→
   162→    // Sparkline + throughput.
   163→    let samples: Vec<u8> = app.throughput.iter().copied().collect();
   164→    let sparkline = build_sparkline(&samples);
   165→    let latest = samples.last().copied().unwrap_or(0);
   166→
   167→    spans.push(Span::styled(" · ", Style::default().fg(Color::DarkGray)));
   168→    spans.push(Span::styled(sparkline, Style::default().fg(Color::Cyan)));
   169→    spans.push(Span::styled(
   170→        format!(" {}/hr", latest),
   171→        Style::default().fg(Color::DarkGray),
   172→    ));
   173→
   174→    let line1 = Line::from(spans);
   175→
   176→    // ── Line 2: event ticker (width >= 120 only) ───────────────────
   177→    let lines = if area.height >= 2 && width >= 120 {
   178→        let completions: Vec<String> = app.recent_completions.iter().cloned().collect();
   179→        let ticker_text = build_ticker_text(&completions, app.tick_count as usize, width);
   180→        let line2 = Line::from(Span::styled(
   181→            ticker_text,
   182→            Style::default().fg(Color::DarkGray),
   183→        ));
   184→        vec![line1, line2]
   185→    } else if area.height >= 2 {
   186→        // Second line is blank when width < 120.
   187→        vec![line1, Line::from("")]
   188→    } else {
   189→        vec![line1]
   190→    };
   191→
   192→    let header = Paragraph::new(lines);
   193→    frame.render_widget(header, area);
   194→}
