   189→    let action_count = app
   190→        .selected_card()
   191→        .map(|c| actions_for_state(&c.state).len())
   192→        .unwrap_or(0);
   193→
   194→    match key.code {
   195→        KeyCode::Char('j') | KeyCode::Down => {
   196→            if action_count > 0 {
   197→                let current = app.action_list_state.selected().unwrap_or(0);
   198→                let next = if current >= action_count - 1 {
   199→                    0
   200→                } else {
   201→                    current + 1
   202→                };
   203→                app.action_list_state.select(Some(next));
   204→            }
   205→        }
   206→        KeyCode::Char('k') | KeyCode::Up => {
   207→            if action_count > 0 {
   208→                let current = app.action_list_state.selected().unwrap_or(0);
   209→                let prev = if current == 0 {
   210→                    action_count - 1
   211→                } else {
   212→                    current - 1
   213→                };
   214→                app.action_list_state.select(Some(prev));
   215→            }
   216→        }
   217→        KeyCode::Enter => {
   218→            // Execute the selected action.
   219→            // When cards are marked, bulk actions apply to all marked cards.
   220→            if let Some(selected_idx) = app.action_list_state.selected() {
   221→                if let Some(card) = app.selected_card() {
   222→                    let actions = actions_for_state(&card.state);
   223→                    if let Some(action) = actions.get(selected_idx) {
   224→                        match action.kind {
   225→                            ActionKind::Logs => {
   226→                                // Logs only apply to the selected card (not bulk).
   227→                                app.enter_log_tail();
   228→                                return;
   229→                            }
   230→                            ActionKind::Pause => {
   231→                                let targets = app.action_target_ids();
   232→                                for id in &targets {
   233→                                    dispatch_action_pause(app, id);
   234→                                }
   235→                                app.clear_marks();
   236→                                app.mode = Mode::Normal;


