   118→
   119→/// Determine title color based on state and WIP saturation.
   120→///
   121→/// Running column with WIP limit: amber at ≥75%, red at 100%.
   122→/// All other columns use their default state color.
   123→fn title_color(col: &KanbanColumn) -> Color {
   124→    if col.state == "running" && col.wip_limit.is_some() {
   125→        let sat = col.wip_saturation();
   126→        if sat >= 1.0 {
   127→            Color::Red
   128→        } else if sat >= 0.75 {
