     1→/// Header bar widget — top 2 rows of the three-zone TUI layout.
     2→///
     3→/// Line 1: `bop · HH:MM:SS · {provider meters} · {sparkline} N/hr`
     4→/// Line 2 (width ≥ 120): scrolling event ticker of recent card completions.
     5→///
     6→/// Provider meters show one bar per provider from `providers.json`, colored:
     7→/// - Green: available
     8→/// - Amber: busy (has a running card)
     9→/// - Red: rate-limited / in cooldown
    10→///
    11→/// Sparkline uses last 8 throughput samples: ▁▂▃▄▅▆▇█
    12→use chrono::Local;
    13→use ratatui::layout::Rect;
    14→use ratatui::style::{Color, Style};
    15→use ratatui::text::{Line, Span};
    16→use ratatui::widgets::Paragraph;
    17→use ratatui::Frame;
    18→
    19→use crate::ui::app::App;
    20→
    21→// ── Provider status ─────────────────────────────────────────────────────────
    22→
    23→/// Provider status for header bar meters.
    24→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    25→pub enum ProviderStatus {
    26→    /// Provider is available (green).
    27→    Available,
    28→    /// Provider has a running card (amber).
    29→    Busy,
    30→    /// Provider is rate-limited or in cooldown (red).
    31→    RateLimited,
    32→}
    33→
    34→/// One entry in the provider meter bar.
    35→#[derive(Debug, Clone)]
    36→#[allow(dead_code)]
    37→pub struct ProviderMeter {
    38→    pub name: String,
    39→    pub status: ProviderStatus,
    40→}
    41→
    42→// ── Colors ──────────────────────────────────────────────────────────────────
    43→
    44→/// Color for a provider meter based on status.
    45→fn meter_color(status: ProviderStatus) -> Color {
    46→    match status {
    47→        ProviderStatus::Available => Color::Green,
    48→        ProviderStatus::Busy => Color::Yellow,
    49→        ProviderStatus::RateLimited => Color::Red,
    50→    }
    51→}
    52→
    53→// ── Sparkline ───────────────────────────────────────────────────────────────
    54→
    55→/// Sparkline block characters ordered by magnitude (index 0 = lowest).
    56→const SPARK_CHARS: [char; 8] = ['▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
    57→
    58→/// Convert a throughput value to a sparkline character.
    59→///
    60→/// Maps `value` into the 0–7 range based on `max_val`. If `max_val` is 0
    61→/// all values map to the lowest bar (▁).
    62→fn spark_char(value: u8, max_val: u8) -> char {
    63→    if max_val == 0 {
    64→        return SPARK_CHARS[0];
    65→    }
    66→    let idx = ((value as usize) * 7) / (max_val as usize);
    67→    SPARK_CHARS[idx.min(7)]
    68→}
    69→
    70→/// Build a sparkline string from a slice of throughput samples.
    71→fn build_sparkline(samples: &[u8]) -> String {
    72→    let max_val = samples.iter().copied().max().unwrap_or(0);
    73→    samples.iter().map(|&v| spark_char(v, max_val)).collect()
    74→}
    75→
    76→// ── Provider meter bar ──────────────────────────────────────────────────────
    77→
    78→/// Width of each provider meter in block characters.
    79→const METER_WIDTH: usize = 4;
    80→
    81→/// Build Spans for all provider meters.
    82→///
    83→/// Each provider gets `METER_WIDTH` block chars: filled (█) in the
    84→/// provider's status color, followed by empty (░) in dark gray to fill
    85→/// any remaining width. Since each meter is binary (status indicator,
    86→/// not a gauge), we fill all blocks in the status color.
    87→fn build_meter_spans(meters: &[ProviderMeter]) -> Vec<Span<'static>> {
    88→    let mut spans = Vec::new();
    89→    for (i, meter) in meters.iter().enumerate() {
    90→        if i > 0 {
    91→            spans.push(Span::raw(" "));
    92→        }
    93→        let color = meter_color(meter.status);
    94→        let filled = "█".repeat(METER_WIDTH);
    95→        spans.push(Span::styled(filled, Style::default().fg(color)));
    96→    }
    97→    spans
    98→}
