   100→// ── Event ticker ────────────────────────────────────────────────────────────
   101→
   102→/// Maximum number of recent completions stored for the event ticker.
   103→pub const TICKER_CAPACITY: usize = 20;
   104→
   105→/// Separator between ticker entries.
   106→const TICKER_SEP: &str = "  ·  ";
   107→
   108→/// Build the scrolling event ticker string from recent completions.
   109→///
   110→/// Joins all entries with a separator, then uses `tick_offset` to scroll
   111→/// the text left across the available width (demoscene-style marquee).
   112→fn build_ticker_text(completions: &[String], tick_offset: usize, width: usize) -> String {
   113→    if completions.is_empty() || width == 0 {
   114→        return String::new();
   115→    }
   116→
   117→    let joined = completions.join(TICKER_SEP);
   118→    if joined.is_empty() {
   119→        return String::new();
   120→    }
   121→
   122→    // Create a repeating buffer so the scroll wraps smoothly.
   123→    let padded = format!("{}{}{}", joined, TICKER_SEP, joined);
   124→    let total_len = padded.chars().count();
   125→    let offset = tick_offset % total_len;
   126→
   127→    padded.chars().cycle().skip(offset).take(width).collect()
   128→}
