   130→// ── Main render ─────────────────────────────────────────────────────────────
   131→
   132→/// Render the header bar into the given area.
   133→///
   134→/// Uses the first row for the main status line and the second row for
   135→/// the scrolling event ticker (only if terminal width ≥ 120).
   136→pub fn render_header(frame: &mut Frame, area: Rect, app: &App) {
   137→    if area.height == 0 || area.width == 0 {
   138→        return;
   139→    }
   140→
   141→    let width = area.width as usize;
   142→
   143→    // ── Line 1: bop · HH:MM:SS · meters · sparkline N/hr ──────────
   144→    let time_str = Local::now().format("%H:%M:%S").to_string();
   145→
   146→    let mut spans: Vec<Span<'static>> = vec![
   147→        Span::styled("bop", Style::default().fg(Color::Cyan)),
   148→        Span::styled(" · ", Style::default().fg(Color::DarkGray)),
   149→        Span::styled(time_str, Style::default().fg(Color::White)),
   150→    ];
   151→
   152→    // Provider meters.
   153→    if !app.provider_meters.is_empty() {
   154→        spans.push(Span::styled(" · ", Style::default().fg(Color::DarkGray)));
   155→        spans.extend(build_meter_spans(&app.provider_meters));
   156→    }
   157→
   158→    // Sparkline + throughput.
   159→    let samples: Vec<u8> = app.throughput.iter().copied().collect();
   160→    let sparkline = build_sparkline(&samples);
   161→    let latest = samples.last().copied().unwrap_or(0);
   162→
   163→    spans.push(Span::styled(" · ", Style::default().fg(Color::DarkGray)));
   164→    spans.push(Span::styled(sparkline, Style::default().fg(Color::Cyan)));
   165→    spans.push(Span::styled(
   166→        format!(" {}/hr", latest),
   167→        Style::default().fg(Color::DarkGray),
   168→    ));
   169→
   170→    let line1 = Line::from(spans);
   171→
   172→    // ── Line 2: event ticker (width >= 120 only) ───────────────────
   173→    let lines = if area.height >= 2 && width >= 120 {
   174→        let completions: Vec<String> = app.recent_completions.iter().cloned().collect();
   175→        let ticker_text = build_ticker_text(&completions, app.tick_count as usize, width);
   176→        let line2 = Line::from(Span::styled(
   177→            ticker_text,
   178→            Style::default().fg(Color::DarkGray),
   179→        ));
   180→        vec![line1, line2]
   181→    } else if area.height >= 2 {
   182→        // Second line is blank when width < 120.
   183→        vec![line1, Line::from("")]
   184→    } else {
   185→        vec![line1]
   186→    };
   187→
   188→    let header = Paragraph::new(lines);
   189→    frame.render_widget(header, area);
   190→}
