     1→/// Action popup overlay widget — centered command palette for card actions.
     2→///
     3→/// Renders as a centered popup overlay using ratatui `Clear` + bordered
     4→/// `Block`. Shows a list of actions filtered by the selected card's state:
     5→///
     6→/// - **running**: `[F3]logs  [z]zellij  [p]pause  [k]kill`
     7→/// - **done**: `[r]retry`
     8→/// - **failed**: `[r]retry`
     9→/// - **pending**: `[k]kill(remove)`
    10→///
    11→/// Each action is a selectable `List` item. Press `↵` in Normal mode to
    12→/// enter `Mode::ActionPopup`; `Esc` returns to Normal. Selecting an action
    13→/// with `↵` executes it (actions are dispatched via `ActionKind`).
    14→use ratatui::layout::Rect;
    15→use ratatui::style::{Color, Modifier, Style};
    16→use ratatui::text::{Line, Span};
    17→use ratatui::widgets::{Block, Clear, List, ListItem, ListState};
    18→use ratatui::Frame;
    19→
    20→// ── Action types ────────────────────────────────────────────────────────────
    21→
    22→/// The kind of action a user can perform on a card.
    23→///
    24→/// Each variant maps to an existing `cmd_*` function in `cards.rs` or
    25→/// a mode transition (e.g. `LogTail` opens the log tail overlay).
    26→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    27→pub enum ActionKind {
    28→    /// Open log tail overlay (F3 / `Mode::LogTail`).
    29→    Logs,
    30→    /// Open card worktree in a Zellij pane.
    31→    Zellij,
    32→    /// Pause a running card (`cmd_pause`).
    33→    Pause,
    34→    /// Kill a running card (`cmd_kill`).
    35→    Kill,
    36→    /// Retry a done/failed card (`cmd_retry`).
    37→    Retry,
    38→    /// Remove a pending card from the queue.
    39→    Remove,
    40→}
    41→
    42→/// A single action entry in the popup list.
    43→#[derive(Debug, Clone)]
    44→#[allow(dead_code)]
    45→pub struct ActionEntry {
    46→    /// The action kind (used for dispatch).
    47→    pub kind: ActionKind,
    48→    /// Keybinding hint shown in the list (e.g. "[F3]").
    49→    pub key_hint: &'static str,
    50→    /// Human-readable label (e.g. "logs").
    51→    pub label: &'static str,
    52→}
    53→
    54→// ── State-filtered action lists ─────────────────────────────────────────────
    55→
    56→/// Return the list of actions available for a given card state.
    57→///
    58→/// Actions are filtered based on what makes sense for the card's current
    59→/// lifecycle state:
    60→/// - `running` → logs, zellij, pause, kill
    61→/// - `done` → retry
    62→/// - `failed` → retry
    63→/// - `pending` → kill(remove)
    64→/// - `merged` → (no actions)
    65→pub fn actions_for_state(state: &str) -> Vec<ActionEntry> {
    66→    match state {
    67→        "running" => vec![
    68→            ActionEntry {
    69→                kind: ActionKind::Logs,
    70→                key_hint: "[F3]",
    71→                label: "logs",
    72→            },
    73→            ActionEntry {
    74→                kind: ActionKind::Zellij,
    75→                key_hint: "[z]",
    76→                label: "zellij",
    77→            },
    78→            ActionEntry {
    79→                kind: ActionKind::Pause,
    80→                key_hint: "[p]",
    81→                label: "pause",
    82→            },
    83→            ActionEntry {
    84→                kind: ActionKind::Kill,
    85→                key_hint: "[k]",
    86→                label: "kill",
    87→            },
    88→        ],
    89→        "done" => vec![ActionEntry {
    90→            kind: ActionKind::Retry,
    91→            key_hint: "[r]",
    92→            label: "retry",
    93→        }],
    94→        "failed" => vec![ActionEntry {
    95→            kind: ActionKind::Retry,
    96→            key_hint: "[r]",
    97→            label: "retry",
    98→        }],
    99→        "pending" => vec![ActionEntry {
   100→            kind: ActionKind::Remove,
   101→            key_hint: "[k]",
   102→            label: "kill (remove)",
   103→        }],
   104→        _ => vec![], // merged or unknown — no actions
   105→    }
   106→}
   107→
   108→// ── Rendering ───────────────────────────────────────────────────────────────
   109→
   110→/// Render the action popup overlay centered in the given body area.
   111→///
   112→/// Uses ratatui `Clear` to erase the underlying kanban content, then draws
   113→/// a bordered `Block` with a selectable `List` of state-filtered actions.
   114→///
   115→/// The popup is sized to fit the action list: width is clamped between
   116→/// 30 and 50 characters, height is the action count + 2 (for borders).
   117→#[allow(dead_code)]
   118→pub fn render_action_popup(
   119→    frame: &mut Frame,
   120→    body_area: Rect,
   121→    card_state: &str,
   122→    card_id: &str,
   123→    action_list_state: &mut ListState,
   124→) {
   125→    let actions = actions_for_state(card_state);
   126→
   127→    if actions.is_empty() {
   128→        // No actions available — render a small "no actions" popup.
   129→        render_empty_popup(frame, body_area, card_id);
   130→        return;
   131→    }
   132→
   133→    // Popup dimensions.
   134→    let popup_width = 36u16.min(body_area.width.saturating_sub(4));
   135→    let popup_height = (actions.len() as u16 + 2).min(body_area.height.saturating_sub(2));
   136→
   137→    let popup_area = centered_rect(popup_width, popup_height, body_area);
   138→
   139→    // Clear the underlying content.
   140→    frame.render_widget(Clear, popup_area);
   141→
   142→    // Build the bordered block with title.
   143→    let title = format!(" {} ", card_id);
   144→    let block = Block::bordered()
   145→        .title(title)
   146→        .title_style(
   147→            Style::default()
   148→                .fg(Color::Yellow)
   149→                .add_modifier(Modifier::BOLD),
   150→        )
   151→        .border_style(Style::default().fg(Color::Yellow));
   152→
   153→    // Build list items from actions.
   154→    let items: Vec<ListItem> = actions
   155→        .iter()
   156→        .map(|action| {
   157→            let line = Line::from(vec![
   158→                Span::styled(
   159→                    format!("{} ", action.key_hint),
   160→                    Style::default().fg(Color::Cyan),
   161→                ),
   162→                Span::styled(action.label, Style::default().fg(Color::White)),
   163→            ]);
   164→            ListItem::new(line)
   165→        })
   166→        .collect();
   167→
   168→    let list = List::new(items)
   169→        .block(block)
   170→        .highlight_style(
   171→            Style::default()
   172→                .fg(Color::Yellow)
   173→                .add_modifier(Modifier::BOLD),
   174→        )
   175→        .highlight_symbol("▸ ");
   176→
   177→    frame.render_stateful_widget(list, popup_area, action_list_state);
   178→}
   179→
