  1→/// Log tail overlay widget — full-height scrollable log view.
  2→///
  3→/// Replaces the body zone when `Mode::LogTail` is active. Shows the last
  4→/// 200 lines from the selected card's `logs/stdout.log` and
  5→/// `logs/stderr.log`. Implements newline-gated streaming: bytes are
  6→/// buffered and only complete lines (ending in `\n`) are emitted to
  7→/// prevent partial ANSI sequence flicker.
  8→///
  9→/// Keybindings (handled in `input.rs`):
 10→/// - `↑` / `↓` — scroll up / down
 11→/// - `f` — toggle follow mode (auto-scroll to bottom)
 12→/// - `c` — clear buffer
 13→/// - `Esc` — return to Normal mode
 14→use std::collections::VecDeque;
 15→
 16→use ratatui::layout::Rect;
 17→use ratatui::style::{Color, Modifier, Style};
 18→use ratatui::text::{Line, Span};
 19→use ratatui::widgets::{Block, Clear, Paragraph, Wrap};
 20→use ratatui::Frame;
 21→
 22→// ── Line styling ────────────────────────────────────────────────────────────
 23→
 24→/// Stylize a single log line for TUI display using ratatui `Style`.
 25→///
 26→/// Mirrors the colorization logic from `logs.rs::colorize_log_line` but
 27→/// uses ratatui styles instead of raw ANSI escape codes, since the TUI
 28→/// owns all terminal rendering via ratatui.
 29→fn stylize_log_line(line: &str) -> Line<'static> {
 30→    let style = if line.contains("ERROR") || line.contains("error:") || line.contains("FAILED") {
 31→        Style::default().fg(Color::Red).add_modifier(Modifier::BOLD)
 32→    } else if line.contains("WARN") || line.contains("warning:") {
 33→        Style::default().fg(Color::Yellow)
 34→    } else if line.contains("INFO") {
 35→        Style::default().fg(Color::Cyan)
 36→    } else if line.contains("DEBUG") || line.contains("TRACE") {
 37→        Style::default().fg(Color::DarkGray)
 38→    } else if line.contains("→ merged") || line.contains("-> merged") {
 39→        Style::default()
 40→            .fg(Color::Magenta)
 41→            .add_modifier(Modifier::BOLD)
 42→    } else if line.contains("→ done") || line.contains("-> done") {
 43→        Style::default()
 44→            .fg(Color::Green)
 45→            .add_modifier(Modifier::BOLD)
 46→    } else if line.contains("→ failed") || line.contains("-> failed") {
 47→        Style::default().fg(Color::Red).add_modifier(Modifier::BOLD)
 48→    } else if line.contains("→ running") || line.contains("-> running") {
 49→        Style::default()
 50→            .fg(Color::Yellow)
 51→            .add_modifier(Modifier::BOLD)
 52→    } else {
 53→        Style::default().fg(Color::White)
 54→    };
 55→
 56→    Line::from(Span::styled(line.to_string(), style))
 57→}
 58→
 59→// ── Public render function ──────────────────────────────────────────────────
 60→
 61→/// Render the log tail overlay, replacing the full body zone.
 62→///
 63→/// Draws a bordered block with the card ID in the title, a follow-mode
 64→/// indicator, and the buffered log lines with scroll support. When
 65→/// `follow_mode` is enabled, the scroll offset is automatically computed
 66→/// to show the most recent lines at the bottom of the viewport.
 67→///
 68→/// The overlay uses ratatui `Clear` to erase the underlying kanban board
 69→/// content before rendering the log view.
 70→pub fn render_logtail(
 71→    frame: &mut Frame,
 72→    body_area: Rect,
 73→    card_id: &str,
 74→    log_buf: &VecDeque<String>,
 75→    log_scroll: usize,
 76→    follow_mode: bool,
 77→) {
 78→    // Clear the entire body area so the kanban content is hidden.
 79→    frame.render_widget(Clear, body_area);
 80→
 81→    // Build title with follow-mode indicator.
 82→    let follow_indicator = if follow_mode { " [FOLLOW]" } else { "" };
 83→    let title = format!(" {} — logs{} ", card_id, follow_indicator);
 84→
 85→    let title_style = if follow_mode {
 86→        Style::default()
 87→            .fg(Color::Green)
 88→            .add_modifier(Modifier::BOLD)
 89→    } else {
 90→        Style::default()
 91→            .fg(Color::Yellow)
 92→            .add_modifier(Modifier::BOLD)
 93→    };
 94→
 95→    let block = Block::bordered()
 96→        .title(title)
 97→        .title_style(title_style)
 98→        .border_style(Style::default().fg(Color::Yellow));
 99→
100→    // Stylize each line from the circular buffer.
101→    let lines: Vec<Line> = log_buf.iter().map(|l| stylize_log_line(l)).collect();
102→
103→    // Calculate effective scroll offset.
104→    // In follow mode, auto-scroll to show the latest lines at the bottom.
105→    let visible_height = body_area.height.saturating_sub(2) as usize; // minus top/bottom borders
106→    let effective_scroll = if follow_mode {
107→        lines.len().saturating_sub(visible_height)
108→    } else {
109→        log_scroll
110→    };
111→
112→    let paragraph = Paragraph::new(lines)
113→        .block(block)
114→        .wrap(Wrap { trim: false })
115→        .scroll((effective_scroll as u16, 0));
116→
117→    frame.render_widget(paragraph, body_area);
118→}
